<script>
// ─── State ────────────────────────────────────────────────────────────────────
let originalArray = [];
let running = false;
let animFrames = { bubble: [], merge: [], quick: [] };

const getSize  = () => +document.getElementById('sizeSlider').value;
const getSpeed = () => +document.getElementById('speedSlider').value;
const delay    = () => Math.max(2, Math.round(300 / (getSpeed() * getSpeed())));

// ─── Helpers ──────────────────────────────────────────────────────────────────
function randArray(n) {
  return Array.from({ length: n }, () => Math.floor(Math.random() * 90) + 10);
}

function renderBars(containerId, arr, highlights = {}) {
  const container = document.getElementById(containerId);
  const maxVal = Math.max(...arr);
  // Reuse existing bars if count matches
  let bars = container.querySelectorAll('.bar');
  if (bars.length !== arr.length) {
    container.innerHTML = '';
    arr.forEach(() => {
      const b = document.createElement('div');
      b.className = 'bar';
      container.appendChild(b);
    });
    bars = container.querySelectorAll('.bar');
  }
  bars.forEach((b, i) => {
    const pct = (arr[i] / maxVal) * 100;
    b.style.height = pct + '%';
    // Color logic
    if (highlights.sorted && highlights.sorted.has(i)) {
      b.style.background = '#6bcb77';
    } else if (highlights.pivot === i) {
      b.style.background = '#ffd93d';
    } else if (highlights.comparing && highlights.comparing.includes(i)) {
      b.style.background = '#ff6b6b';
    } else if (highlights.writing && highlights.writing.includes(i)) {
      b.style.background = '#c77dff';
    } else {
      // Default gradient based on algorithm
      const colors = {
        bubbleChart: 'linear-gradient(180deg,#ff6b6b,#c94040)',
        mergeChart:  'linear-gradient(180deg,#6bcb77,#3a8a44)',
        quickChart:  'linear-gradient(180deg,#4d96ff,#1a5abf)',
      };
      b.style.background = colors[containerId] || '#4d96ff';
    }
  });
}

function setStatus(id, msg, type) {
  const el = document.getElementById(id);
  el.textContent = msg;
  el.className = `status-badge ${type}-badge`;
}

function updateStat(id, val) {
  document.getElementById(id).textContent = val.toLocaleString();
}

// ─── Frame-based animation engine ────────────────────────────────────────────
function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

// ─── BUBBLE SORT ─────────────────────────────────────────────────────────────
async function bubbleSort(arr) {
  const n = arr.length;
  let comparisons = 0, swaps = 0;
  const sorted = new Set();
  const t0 = performance.now();
  setStatus('bStatus', 'Running…', 'running');

  for (let i = 0; i < n - 1; i++) {
    let swapped = false;
    for (let j = 0; j < n - i - 1; j++) {
      if (!running) return;
      comparisons++;
      updateStat('bComparisons', comparisons);
      renderBars('bubbleChart', arr, { comparing: [j, j+1], sorted });
      await sleep(delay());

      if (arr[j] > arr[j + 1]) {
        [arr[j], arr[j+1]] = [arr[j+1], arr[j]];
        swaps++;
        updateStat('bSwaps', swaps);
        swapped = true;
        renderBars('bubbleChart', arr, { comparing: [j, j+1], sorted });
        await sleep(delay());
      }
    }
    sorted.add(n - 1 - i);
    if (!swapped) {
      for (let k = 0; k < n - 1 - i; k++) sorted.add(k);
      break;
    }
  }
  sorted.add(0);
  const elapsed = (performance.now() - t0).toFixed(1);
  document.getElementById('bTime').textContent = elapsed;
  renderBars('bubbleChart', arr, { sorted: new Set(arr.map((_, i) => i)) });
  setStatus('bStatus', `✅ Done in ${elapsed}ms`, 'done');
}

// ─── MERGE SORT ──────────────────────────────────────────────────────────────
async function mergeSort(arr) {
  let comparisons = 0, writes = 0;
  const t0 = performance.now();
  setStatus('mStatus', 'Running…', 'running');

  async function merge(arr, l, m, r) {
    const left  = arr.slice(l, m + 1);
    const right = arr.slice(m + 1, r + 1);
    let i = 0, j = 0, k = l;
    while (i < left.length && j < right.length) {
      if (!running) return;
      comparisons++;
      updateStat('mComparisons', comparisons);
      if (left[i] <= right[j]) {
        arr[k] = left[i++];
      } else {
        arr[k] = right[j++];
      }
      writes++;
      updateStat('mSwaps', writes);
      renderBars('mergeChart', arr, { writing: [k] });
      await sleep(delay());
      k++;
    }
    while (i < left.length) {
      if (!running) return;
      arr[k++] = left[i++];
      writes++;
      updateStat('mSwaps', writes);
      renderBars('mergeChart', arr, { writing: [k-1] });
      await sleep(delay());
    }
    while (j < right.length) {
      if (!running) return;
      arr[k++] = right[j++];
      writes++;
      updateStat('mSwaps', writes);
      renderBars('mergeChart', arr, { writing: [k-1] });
      await sleep(delay());
    }
  }

  async function sort(arr, l, r) {
    if (l >= r || !running) return;
    const m = Math.floor((l + r) / 2);
    await sort(arr, l, m);
    await sort(arr, m + 1, r);
    await merge(arr, l, m, r);
  }

  await sort(arr, 0, arr.length - 1);
  const elapsed = (performance.now() - t0).toFixed(1);
  document.getElementById('mTime').textContent = elapsed;
  renderBars('mergeChart', arr, { sorted: new Set(arr.map((_, i) => i)) });
  setStatus('mStatus', `✅ Done in ${elapsed}ms`, 'done');
}

// ─── QUICK SORT ───────────────────────────────────────────────────────────────
async function quickSort(arr) {
  let comparisons = 0, swaps = 0;
  const t0 = performance.now();
  setStatus('qStatus', 'Running…', 'running');

  async function partition(arr, low, high) {
    // Median-of-three pivot
    const mid = Math.floor((low + high) / 2);
    if (arr[mid] < arr[low]) [arr[low], arr[mid]] = [arr[mid], arr[low]];
    if (arr[high] < arr[low]) [arr[low], arr[high]] = [arr[high], arr[low]];
    if (arr[mid] < arr[high]) [arr[mid], arr[high]] = [arr[high], arr[mid]];
    const pivot = arr[high];
    let i = low - 1;

    for (let j = low; j < high; j++) {
      if (!running) return i;
      comparisons++;
      updateStat('qComparisons', comparisons);
      renderBars('quickChart', arr, { comparing: [j], pivot: high });
      await sleep(delay());
      if (arr[j] <= pivot) {
        i++;
        [arr[i], arr[j]] = [arr[j], arr[i]];
        swaps++;
        updateStat('qSwaps', swaps);
        renderBars('quickChart', arr, { comparing: [i, j], pivot: high });
        await sleep(delay());
      }
    }
    [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
    swaps++;
    updateStat('qSwaps', swaps);
    return i + 1;
  }

  async function sort(arr, low, high) {
    if (low < high && running) {
      const pi = await partition(arr, low, high);
      await sort(arr, low, pi - 1);
      await sort(arr, pi + 1, high);
    }
  }

  await sort(arr, 0, arr.length - 1);
  const elapsed = (performance.now() - t0).toFixed(1);
  document.getElementById('qTime').textContent = elapsed;
  renderBars('quickChart', arr, { sorted: new Set(arr.map((_, i) => i)) });
  setStatus('qStatus', `✅ Done in ${elapsed}ms`, 'done');
}

// ─── Controls ─────────────────────────────────────────────────────────────────
function initArray() {
  originalArray = randArray(getSize());
  ['bComparisons','bSwaps','bTime','mComparisons','mSwaps','mTime','qComparisons','qSwaps','qTime']
    .forEach(id => {
      document.getElementById(id).textContent = id.endsWith('Time') ? '—' : '0';
    });
  ['bStatus','mStatus','qStatus'].forEach(id => setStatus(id, 'Idle', 'idle'));
  document.getElementById('winnerBanner').classList.remove('show');
  renderBars('bubbleChart', [...originalArray]);
  renderBars('mergeChart',  [...originalArray]);
  renderBars('quickChart',  [...originalArray]);
}

async function startSort() {
  if (running) return;
  running = true;
  document.getElementById('btnStart').disabled = true;
  document.getElementById('btnNew').disabled = true;

  const bArr = [...originalArray];
  const mArr = [...originalArray];
  const qArr = [...originalArray];

  await Promise.all([
    bubbleSort(bArr),
    mergeSort(mArr),
    quickSort(qArr),
  ]);

  running = false;
  document.getElementById('btnStart').disabled = false;
  document.getElementById('btnNew').disabled = false;

  // Show winner
  const bT = parseFloat(document.getElementById('bTime').textContent) || Infinity;
  const mT = parseFloat(document.getElementById('mTime').textContent) || Infinity;
  const qT = parseFloat(document.getElementById('qTime').textContent) || Infinity;
  const minT = Math.min(bT, mT, qT);
  const winners = [];
  if (bT === minT) winners.push('🫧 Bubble Sort');
  if (mT === minT) winners.push('🔀 Merge Sort');
  if (qT === minT) winners.push('⚡ Quick Sort');

  const bC = +document.getElementById('bComparisons').textContent.replace(/,/g,'');
  const mC = +document.getElementById('mComparisons').textContent.replace(/,/g,'');
  const qC = +document.getElementById('qComparisons').textContent.replace(/,/g,'');

  const banner = document.getElementById('winnerBanner');
  banner.innerHTML = `
    <strong>🏁 Race Complete!</strong><br>
    Fastest: <strong>${winners.join(' & ')}</strong> (${minT}ms) &nbsp;|&nbsp;
    Comparisons → Bubble: ${bC.toLocaleString()} &nbsp; Merge: ${mC.toLocaleString()} &nbsp; Quick: ${qC.toLocaleString()}<br>
    <span style="color:#ffd93d;font-size:0.8rem">
      ${bC > qC * 2 ? '⚠️ Bubble needed ' + Math.round(bC/Math.max(qC,1)) + '× more comparisons than Quick Sort!' : ''}
    </span>
  `;
  banner.classList.add('show');
}

function resetSort() {
  running = false;
  setTimeout(() => {
    initArray();
    document.getElementById('btnStart').disabled = false;
    document.getElementById('btnNew').disabled = false;
  }, 100);
}

document.getElementById('btnStart').addEventListener('click', startSort);
document.getElementById('btnReset').addEventListener('click', resetSort);
document.getElementById('btnNew').addEventListener('click', () => { if (!running) initArray(); });

document.getElementById('sizeSlider').addEventListener('input', function() {
  document.getElementById('sizeLabel').textContent = this.value;
  if (!running) initArray();
});
document.getElementById('speedSlider').addEventListener('input', function() {
  document.getElementById('speedLabel').textContent = this.value;
});

// Init
initArray();
</script>
</body>
</html>
```

## What's inside this file

**Three side-by-side animated panels** showing:
- 🫧 **Bubble Sort** — bars highlighted in red as adjacent pairs are compared/swapped
- 🔀 **Merge Sort** — purple highlights show where values are being written during merges
- ⚡ **Quick Sort** — yellow pivot bar + red comparison highlights

**Live counters per algorithm:**
| Stat | Bubble | Merge | Quick |
|---|---|---|---|
| Comparisons | ✅ | ✅ | ✅ |
| Swaps/Writes | ✅ | ✅ | ✅ |
| Time (ms) | ✅ | ✅ | ✅ |

**Controls:**
- **Array size slider** (10–80 elements)
- **Speed slider** (1–10)
- **New Array**, **Start**, and **Reset** buttons

**Post-race banner** announces the winner and shows how many times more comparisons Bubble Sort needed vs Quick Sort.

**Complexity reference cards** at the bottom explain Best/Average/Worst/Space complexity and stability for each algorithm with plain-English descriptions.

