<script>
    // ─── State ───────────────────────────────────────────────────────────────
    let masterArray = [];
    let isRunning = false;
    let finishTimes = {};
    let finishOrder = [];

    const sizeSlider = document.getElementById('sizeSlider');
    const speedSlider = document.getElementById('speedSlider');
    const sizeVal = document.getElementById('sizeVal');
    const speedVal = document.getElementById('speedVal');
    const startBtn = document.getElementById('startBtn');
    const resetBtn = document.getElementById('resetBtn');

    const speedLabels = ['', 'Glacial', 'Very Slow', 'Slow', 'Moderate', 'Medium', 'Fast', 'Faster', 'Very Fast', 'Blazing', 'Instant'];

    // ─── Helpers ─────────────────────────────────────────────────────────────
    function getDelay() {
        const s = parseInt(speedSlider.value);
        // Map 1-10 → large delay to tiny delay
        const delays = [0, 300, 150, 80, 40, 20, 10, 5, 2, 1, 0];
        return delays[s];
    }

    function sleep(ms) {
        return new Promise(r => setTimeout(r, ms));
    }

    function randomArray(n) {
        return Array.from({ length: n }, () => Math.floor(Math.random() * 95) + 5);
    }

    function renderBars(containerId, arr, highlights = {}) {
        const container = document.getElementById(containerId);
        // Remove old bars (keep overlay)
        const overlay = container.querySelector('.done-overlay');
        container.innerHTML = '';
        container.appendChild(overlay);

        const maxVal = Math.max(...arr);
        arr.forEach((val, i) => {
            const bar = document.createElement('div');
            bar.className = 'bar';
            bar.style.height = `${(val / maxVal) * 96}%`;

            if (highlights.comparing && highlights.comparing.includes(i)) {
                bar.style.background = '#ff6b6b';
                bar.style.boxShadow = '0 0 6px #ff6b6b88';
            } else if (highlights.pivot === i) {
                bar.style.background = '#ffd93d';
                bar.style.boxShadow = '0 0 6px #ffd93d88';
            } else if (highlights.sorted && highlights.sorted.includes(i)) {
                bar.style.background = '#6bcb77';
            } else if (highlights.merging && highlights.merging.includes(i)) {
                bar.style.background = '#00d4ff';
                bar.style.boxShadow = '0 0 6px #00d4ff66';
            } else {
                // Default gradient based on value
                const pct = val / maxVal;
                bar.style.background = `hsl(${200 + pct * 60}, 70%, 55%)`;
            }
            container.appendChild(bar);
        });
    }

    function showDone(algoId, color) {
        const overlay = document.getElementById(`done-${algoId}`);
        overlay.style.background = `${color}22`;
        overlay.style.color = color;
        overlay.style.opacity = '1';
        overlay.style.border = `1px solid ${color}44`;
    }

    function updateStat(algoId, stat, val) {
        document.getElementById(`${stat}-${algoId}`).textContent = val;
    }

    function updateStatus(algoId, text) {
        document.getElementById(`status-${algoId}`).textContent = text;
    }

    function recordFinish(algoId) {
        finishOrder.push(algoId);
        if (finishOrder.length === 3) {
            showWinnerBanner();
        }
    }

    function showWinnerBanner() {
        const names = { bubble: '🐢 Bubble Sort', merge: '🐇 Merge Sort', quick: '🚀 Quick Sort' };
        const winner = names[finishOrder[0]];
        const banner = document.getElementById('winnerBanner');
        banner.style.display = 'block';
        banner.textContent = `🏆 ${winner} finished first! Order: ${finishOrder.map(a => names[a]).join(' → ')}`;
    }

    // ─── Generate & Render ───────────────────────────────────────────────────
    function generateAndRender() {
        const n = parseInt(sizeSlider.value);
        masterArray = randomArray(n);
        ['bubble', 'merge', 'quick'].forEach(id => {
            renderBars(`chart-${id}`, [...masterArray]);
            updateStat(id, 'steps', 0);
            updateStat(id, 'swaps', 0);
            updateStat(id, 'time', '—');
            updateStatus(id, 'Ready');
            const overlay = document.getElementById(`done-${id}`);
            overlay.style.opacity = '0';
        });
        document.getElementById('winnerBanner').style.display = 'none';
        finishOrder = [];
        finishTimes = {};
    }

    // ─── Bubble Sort ─────────────────────────────────────────────────────────
    async function bubbleSort(arr) {
        const id = 'bubble';
        const n = arr.length;
        let comparisons = 0;
        let swaps = 0;
        const delay = getDelay();
        const startTime = performance.now();
        const sorted = new Set();

        updateStatus(id, 'Sorting...');

        for (let i = 0; i < n - 1; i++) {
            let swapped = false;
            for (let j = 0; j < n - i - 1; j++) {
                comparisons++;
                updateStat(id, 'steps', comparisons);

                renderBars(`chart-${id}`, arr, {
                    comparing: [j, j + 1],
                    sorted: [...sorted].concat(
                        Array.from({ length: i }, (_, k) => n - 1 - k)
                    )
                });

                if (arr[j] > arr[j + 1]) {
                    [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
                    swaps++;
                    swapped = true;
                    updateStat(id, 'swaps', swaps);
                }

                if (delay > 0) await sleep(delay);
            }
            sorted.add(n - 1 - i);
            if (!swapped) break;
        }

        const elapsed = (performance.now() - startTime).toFixed(1);
        updateStat(id, 'time', elapsed);
        renderBars(`chart-${id}`, arr, { sorted: arr.map((_, i) => i) });
        showDone(id, '#ff6b6b');
        updateStatus(id, `Done! ${comparisons} comparisons, ${swaps} swaps`);
        recordFinish(id);
    }

    // ─── Merge Sort ──────────────────────────────────────────────────────────
    async function mergeSort(arr) {
        const id = 'merge';
        let comparisons = 0;
        let mergeOps = 0;
        const delay = getDelay();
        const startTime = performance.now();

        updateStatus(id, 'Sorting...');

        async function mergeSortHelper(a, left, right) {
            if (right - left <= 1) return;
            const mid = Math.floor((left + right) / 2);
            await mergeSortHelper(a, left, mid);
            await mergeSortHelper(a, mid, right);
            await merge(a, left, mid, right);
        }

        async function merge(a, left, mid, right) {
            const leftArr = a.slice(left, mid);
            const rightArr = a.slice(mid, right);
            let i = 0, j = 0, k = left;
            const mergingIdx = [];

            while (i < leftArr.length && j < rightArr.length) {
                comparisons++;
                updateStat(id, 'steps', comparisons);
                mergingIdx.push(k);

                if (leftArr[i] <= rightArr[j]) {
                    a[k++] = leftArr[i++];
                } else {
                    a[k++] = rightArr[j++];
                }
                mergeOps++;
                updateStat(id, 'swaps', mergeOps);

                renderBars(`chart-${id}`, a, { merging: [k - 1] });
                if (delay > 0) await sleep(delay);
            }

            while (i < leftArr.length) {
                a[k++] = leftArr[i++];
                mergeOps++;
                updateStat(id, 'swaps', mergeOps);
                renderBars(`chart-${id}`, a, { merging: [k - 1] });
                if (delay > 0) await sleep(delay);
            }

            while (j < rightArr.length) {
                a[k++] = rightArr[j++];
                mergeOps++;
                updateStat(id, 'swaps', mergeOps);
                renderBars(`chart-${id}`, a, { merging: [k - 1] });
                if (delay > 0) await sleep(delay);
            }
        }

        await mergeSortHelper(arr, 0, arr.length);

        const elapsed = (performance.now() - startTime).toFixed(1);
        updateStat(id, 'time', elapsed);
        renderBars(`chart-${id}`, arr, { sorted: arr.map((_, i) => i) });
        showDone(id, '#ffd93d');
        updateStatus(id, `Done! ${comparisons} comparisons, ${mergeOps} merges`);
        recordFinish(id);
    }

    // ─── Quick Sort ──────────────────────────────────────────────────────────
    async function quickSort(arr) {
        const id = 'quick';
        let comparisons = 0;
        let swaps = 0;
        const delay = getDelay();
        const startTime = performance.now();
        const sorted = new Set();

        updateStatus(id, 'Sorting...');

        async function quickSortHelper(a, low, high) {
            if (low >= high) {
                if (low === high) sorted.add(low);
                return;
            }
            const pivotIdx = await partition(a, low, high);
            sorted.add(pivotIdx);
            await quickSortHelper(a, low, pivotIdx - 1);
            await quickSortHelper(a, pivotIdx + 1, high);
        }

        async function partition(a, low, high) {
            // Randomized pivot to avoid worst case
            const randIdx = low + Math.floor(Math.random() * (high - low + 1));
            [a[randIdx], a[high]] = [a[high], a[randIdx]];

            const pivot = a[high];
            let i = low - 1;

            for (let j = low; j < high; j++) {
                comparisons++;
                updateStat(id, 'steps', comparisons);

                renderBars(`chart-${id}`, a, {
                    comparing: [j, i + 1],
                    pivot: high,
                    sorted: [...sorted]
                });

                if (a[j] <= pivot) {
                    i++;
                    [a[i], a[j]] = [a[j], a[i]];
                    swaps++;
                    updateStat(id, 'swaps', swaps);
                }

                if (delay > 0) await sleep(delay);
            }

            [a[i + 1], a[high]] = [a[high], a[i + 1]];
            swaps++;
            updateStat(id, 'swaps', swaps);
            return i + 1;
        }

        await quickSortHelper(arr, 0, arr.length - 1);

        const elapsed = (performance.now() - startTime).toFixed(1);
        updateStat(id, 'time', elapsed);
        renderBars(`chart-${id}`, arr, { sorted: arr.map((_, i) => i) });
        showDone(id, '#6bcb77');
        updateStatus(id, `Done! ${comparisons} comparisons, ${swaps} swaps`);
        recordFinish(id);
    }

    // ─── Event Listeners ─────────────────────────────────────────────────────
    sizeSlider.addEventListener('input', () => {
        sizeVal.textContent = sizeSlider.value;
        if (!isRunning) generateAndRender();
    });

    speedSlider.addEventListener('input', () => {
        speedVal.textContent = speedLabels[speedSlider.value];
    });

    resetBtn.addEventListener('click', () => {
        if (!isRunning) generateAndRender();
    });

    startBtn.addEventListener('click', async () => {
        if (isRunning) return;
        isRunning = true;
        startBtn.disabled = true;
        resetBtn.disabled = true;
        finishOrder = [];
        document.getElementById('winnerBanner').style.display = 'none';

        // Each algo gets its own copy of the array
        const arrBubble = [...masterArray];
        const arrMerge = [...masterArray];
        const arrQuick = [...masterArray];

        // Run all three concurrently
        await Promise.all([
            bubbleSort(arrBubble),
            mergeSort(arrMerge),
            quickSort(arrQuick)
        ]);

        isRunning = false;
        startBtn.disabled = false;
        resetBtn.disabled = false;
        startBtn.textContent = '▶ Sort Again';
    });

    // ─── Init ────────────────────────────────────────────────────────────────
    speedVal.textContent = speedLabels[speedSlider.value];
    generateAndRender();
</script>
</body>
</html>
```

## What this does:

**Three side-by-side panels** running concurrently on identical data:
- 🐢 **Bubble Sort** — highlighted in red, painfully visible at slower speeds
- 🐇 **Merge Sort** — yellow, shows the divide-and-conquer merging in cyan
- 🚀 **Quick Sort** — green, shows pivot (yellow bar) and partition comparisons

**Interactive controls:**
- **Array Size** slider (20–100 elements)
- **Speed** slider (Glacial → Instant) — slow it way down to really see the difference
- **New Array** button to shuffle
- **Start Sort** runs all three simultaneously

**Live stats per algorithm:** comparison count, swap/merge count, and elapsed time in ms

**Winner banner** announces finish order when all three complete

**Complexity reference cards** at the bottom explain Big O with best/average/worst case tables

> 💡 **Teaching tip:** Set speed to "Slow" or "Moderate" with ~50 elements — you can *watch* Bubble Sort still grinding away while Merge and Quick Sort are already done!

