        <th>Space</th>
        <th>Stable?</th>
      </tr>
    </thead>
    <tbody>
      <tr class="bubble-row">
        <td class="algo-name">Bubble Sort</td>
        <td class="ok">O(n)</td>
        <td class="bad">O(n²)</td>
        <td class="bad">O(n²)</td>
        <td class="good">O(1)</td>
        <td class="good">Yes</td>
      </tr>
      <tr class="merge-row">
        <td class="algo-name">Merge Sort</td>
        <td class="good">O(n log n)</td>
        <td class="good">O(n log n)</td>
        <td class="good">O(n log n)</td>
        <td class="ok">O(n)</td>
        <td class="good">Yes</td>
