<script>
// ─── Configuration ────────────────────────────────────────────────────────────
const ALGORITHMS = [
  {
    id: 'bubble',
    name: 'Bubble Sort',
    badge: 'SLOW',
    badgeClass: 'badge-slow',
    color: '#ff6b6b',
    complexity: 'O(n²) avg/worst',
    generate: bubbleSortSteps,
  },
  {
    id: 'merge',
    name: 'Merge Sort',
    badge: 'FAST',
    badgeClass: 'badge-fast',
    color: '#6bcb77',
    complexity: 'O(n log n) guaranteed',
    generate: mergeSortSteps,
  },
  {
    id: 'quick',
    name: 'Quick Sort',
    badge: 'FAST',
    badgeClass: 'badge-fast',
    color: '#4d96ff',
    complexity: 'O(n log n) avg',
    generate: quickSortSteps,
  },
];

const SPEED_LABELS = ['Very Slow', 'Slow', 'Normal', 'Fast', 'Blazing'];
const SPEED_DELAYS = [300, 120, 40, 12, 2];

// ─── State ────────────────────────────────────────────────────────────────────
let baseArray = [];
let algoStates = [];
let animationId = null;
let running = false;

// ─── DOM refs ─────────────────────────────────────────────────────────────────
const sizeSelect   = document.getElementById('sizeSelect');
const speedRange   = document.getElementById('speedRange');
const speedLabel   = document.getElementById('speedLabel');
const btnGenerate  = document.getElementById('btnGenerate');
const btnStart     = document.getElementById('btnStart');
const btnReset     = document.getElementById('btnReset');
const panelsEl     = document.getElementById('panels');

// ─── Speed label update ───────────────────────────────────────────────────────
speedRange.addEventListener('input', () => {
  speedLabel.textContent = SPEED_LABELS[speedRange.value - 1];
});

// ─── Generate new array ───────────────────────────────────────────────────────
function generateArray(n) {
  const arr = Array.from({ length: n }, (_, i) => i + 1);
  // Fisher-Yates shuffle
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

// ─── Build panels ─────────────────────────────────────────────────────────────
function buildPanels() {
  panelsEl.innerHTML = '';
  algoStates = [];

  ALGORITHMS.forEach((algo) => {
    const panel = document.createElement('div');
    panel.className = 'panel';
    panel.innerHTML = `
      <div class="panel-header">
        <span class="panel-title" style="color:${algo.color}">${algo.name}</span>
        <span class="badge ${algo.badgeClass}">${algo.badge}</span>
      </div>
      <div class="complexity">Time complexity: <span>${algo.complexity}</span></div>
      <div class="stats">
        <div class="stat">
          <span class="stat-label">Comparisons</span>
          <span class="stat-value comparisons" id="cmp-${algo.id}">0</span>
        </div>
        <div class="stat">
          <span class="stat-label">Swaps/Writes</span>
          <span class="stat-value swaps" id="swp-${algo.id}">0</span>
        </div>
        <div class="stat">
          <span class="stat-label">Progress</span>
          <span class="stat-value time" id="prg-${algo.id}">0%</span>
        </div>
      </div>
      <div class="chart-wrapper">
        <canvas id="canvas-${algo.id}"></canvas>
        <div class="done-overlay" id="done-${algo.id}">✔ Done!</div>
      </div>
    `;
    panelsEl.appendChild(panel);

    // Build steps
    const arr = baseArray.slice();
    const steps = algo.generate(arr);

    algoStates.push({
      algo,
      steps,
      stepIndex: 0,
      done: false,
      comparisons: 0,
      swaps: 0,
    });
  });

  // Initial draw
  algoStates.forEach((state) => drawStep(state, state.steps[0]));
}

// ─── Canvas drawing ───────────────────────────────────────────────────────────
function drawStep(state, step) {
  const canvas = document.getElementById(`canvas-${state.algo.id}`);
  if (!canvas) return;

  // Sync canvas resolution to CSS size
  const rect = canvas.getBoundingClientRect();
  const W = rect.width  || canvas.offsetWidth  || 300;
  const H = rect.height || canvas.offsetHeight || 180;
  canvas.width  = W;
  canvas.height = H;

  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, W, H);

  const arr = step.array;
  const n   = arr.length;
  const max = Math.max(...arr);
  const gap = 1;
  const barW = (W - gap * (n - 1)) / n;

  arr.forEach((val, i) => {
    const barH = (val / max) * (H - 4);
    const x = i * (barW + gap);
    const y = H - barH;

    let color = '#3a3a6a';

    if (step.sorted && step.sorted.has(i)) {
      color = state.algo.color;
    } else if (step.comparing && step.comparing.includes(i)) {
      color = '#ffd93d';
    } else if (step.swapping && step.swapping.includes(i)) {
      color = '#ff6b6b';
    } else if (step.pivot === i) {
      color = '#ff9f43';
    } else if (step.merging && step.merging.includes(i)) {
      color = '#a29bfe';
    }

    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.roundRect
      ? ctx.roundRect(x, y, Math.max(barW, 1), barH, [2, 2, 0, 0])
      : ctx.rect(x, y, Math.max(barW, 1), barH);
    ctx.fill();
  });
}

// ─── Animation loop ───────────────────────────────────────────────────────────
function tick() {
  const delay = SPEED_DELAYS[speedRange.value - 1];
  let allDone = true;

  algoStates.forEach((state) => {
    if (state.done) return;
    allDone = false;

    const step = state.steps[state.stepIndex];
    drawStep(state, step);

    // Update stats
    if (step.comparisons !== undefined) state.comparisons = step.comparisons;
    if (step.swaps       !== undefined) state.swaps       = step.swaps;

    document.getElementById(`cmp-${state.algo.id}`).textContent =
      state.comparisons.toLocaleString();
    document.getElementById(`swp-${state.algo.id}`).textContent =
      state.swaps.toLocaleString();
    document.getElementById(`prg-${state.algo.id}`).textContent =
      Math.round((state.stepIndex / (state.steps.length - 1)) * 100) + '%';

    state.stepIndex++;
    if (state.stepIndex >= state.steps.length) {
      state.done = true;
      document.getElementById(`done-${state.algo.id}`).classList.add('visible');
      document.getElementById(`prg-${state.algo.id}`).textContent = '100%';
    }
  });

  if (allDone) {
    running = false;
    btnStart.disabled   = true;
    btnReset.disabled   = false;
    btnGenerate.disabled = false;
    return;
  }

  animationId = setTimeout(tick, delay);
}

// ─── Controls ─────────────────────────────────────────────────────────────────
btnGenerate.addEventListener('click', () => {
  stopAnimation();
  const n = parseInt(sizeSelect.value);
  baseArray = generateArray(n);
  buildPanels();
  btnStart.disabled    = false;
  btnReset.disabled    = true;
  btnGenerate.disabled = false;
});

btnStart.addEventListener('click', () => {
  if (running) return;
  running = true;
  btnStart.disabled    = true;
  btnReset.disabled    = false;
  btnGenerate.disabled = true;
  tick();
});

btnReset.addEventListener('click', () => {
  stopAnimation();
  buildPanels();
  btnStart.disabled    = false;
  btnReset.disabled    = true;
  btnGenerate.disabled = false;
});

function stopAnimation() {
  clearTimeout(animationId);
  running = false;
}

// ─── Sorting step generators ──────────────────────────────────────────────────

// Each generator returns an array of "step" objects:
// { array, comparing?, swapping?, sorted?, pivot?, merging?, comparisons, swaps }

function bubbleSortSteps(arr) {
  const steps = [];
  const a = arr.slice();
  const n = a.length;
  const sorted = new Set();
  let comparisons = 0, swaps = 0;

  steps.push({ array: a.slice(), sorted: new Set(sorted), comparisons, swaps });

  for (let i = 0; i < n - 1; i++) {
    let swapped = false;
    for (let j = 0; j < n - i - 1; j++) {
      comparisons++;
      steps.push({
        array: a.slice(), comparing: [j, j + 1],
        sorted: new Set(sorted), comparisons, swaps,
      });

      if (a[j] > a[j + 1]) {
        [a[j], a[j + 1]] = [a[j + 1], a[j]];
        swaps++;
        swapped = true;
        steps.push({
          array: a.slice(), swapping: [j, j + 1],
          sorted: new Set(sorted), comparisons, swaps,
        });
      }
    }
    sorted.add(n - 1 - i);
    steps.push({ array: a.slice(), sorted: new Set(sorted), comparisons, swaps });
    if (!swapped) break;
  }

  // Mark all as sorted
  for (let k = 0; k < n; k++) sorted.add(k);
  steps.push({ array: a.slice(), sorted: new Set(sorted), comparisons, swaps });
  return steps;
}

function mergeSortSteps(arr) {
  const steps = [];
  const a = arr.slice();
  let comparisons = 0, swaps = 0;
  const sorted = new Set();

  steps.push({ array: a.slice(), sorted: new Set(sorted), comparisons, swaps });

  function merge(arr, left, mid, right) {
    const L = arr.slice(left, mid + 1);
    const R = arr.slice(mid + 1, right + 1);
    let i = 0, j = 0, k = left;

    while (i < L.length && j < R.length) {
      comparisons++;
      const merging = [];
      for (let x = left; x <= right; x++) merging.push(x);

      steps.push({
        array: arr.slice(), merging,
        sorted: new Set(sorted), comparisons, swaps,
      });

      if (L[i] <= R[j]) {
        arr[k++] = L[i++];
      } else {
        arr[k++] = R[j++];
      }
      swaps++;
      steps.push({
        array: arr.slice(), merging,
        sorted: new Set(sorted), comparisons, swaps,
      });
    }
    while (i < L.length) { arr[k++] = L[i++]; swaps++; }
    while (j < R.length) { arr[k++] = R[j++]; swaps++; }
  }

  function mergeSort(arr, left, right) {
    if (left >= right) return;
    const mid = Math.floor((left + right) / 2);
    mergeSort(arr, left, mid);
    mergeSort(arr, mid + 1, right);
    merge(arr, left, mid, right);
  }

  mergeSort(a, 0, a.length - 1);

  for (let k = 0; k < a.length; k++) sorted.add(k);
  steps.push({ array: a.slice(), sorted: new Set(sorted), comparisons, swaps });
  return steps;
}

function quickSortSteps(arr) {
  const steps = [];
  const a = arr.slice();
  let comparisons = 0, swaps = 0;
  const sorted = new Set();

  steps.push({ array: a.slice(), sorted: new Set(sorted), comparisons, swaps });

  function partition(arr, low, high) {
    // Median-of-three pivot
    const mid = Math.floor((low + high) / 2);
    const candidates = [[arr[low], low], [arr[mid], mid], [arr[high], high]];
    candidates.sort((x, y) => x[0] - y[0]);
    const pivotIdx = candidates[1][1];
    [arr[pivotIdx], arr[high]] = [arr[high], arr[pivotIdx]];
    swaps++;

    const pivot = arr[high];
    let i = low - 1;

    for (let j = low; j < high; j++) {
      comparisons++;
      steps.push({
        array: arr.slice(), comparing: [j, high], pivot: high,
        sorted: new Set(sorted), comparisons, swaps,
      });
      if (arr[j] <= pivot) {
        i++;
        [arr[i], arr[j]] = [arr[j], arr[i]];
        swaps++;
        steps.push({
          array: arr.slice(), swapping: [i, j], pivot: high,
          sorted: new Set(sorted), comparisons, swaps,
        });
      }
    }
    [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
    swaps++;
    steps.push({
      array: arr.slice(), swapping: [i + 1, high],
      sorted: new Set(sorted), comparisons, swaps,
    });
    return i + 1;
  }

  function quickSort(arr, low, high) {
    if (low < high) {
      const pi = partition(arr, low, high);
      sorted.add(pi);
      steps.push({ array: arr.slice(), sorted: new Set(sorted), comparisons, swaps });
      quickSort(arr, low, pi - 1);
      quickSort(arr, pi + 1, high);
    }
  }

  quickSort(a, 0, a.length - 1);

  for (let k = 0; k < a.length; k++) sorted.add(k);
  steps.push({ array: a.slice(), sorted: new Set(sorted), comparisons, swaps });
  return steps;
}

// ─── Init ─────────────────────────────────────────────────────────────────────
speedLabel.textContent = SPEED_LABELS[speedRange.value - 1];
baseArray = generateArray(parseInt(sizeSelect.value));
buildPanels();
btnReset.disabled = true;

// Redraw on resize
window.addEventListener('resize', () => {
  algoStates.forEach((state) => {
    const step = state.steps[Math.max(0, state.stepIndex - 1)];
    if (step) drawStep(state, step);
  });
});
</script>
</body>
</html>
```

### What this demo does

| Feature | Details |
|---|---|
| **3 algorithms** | Bubble Sort, Merge Sort, Quick Sort running on identical data |
| **Live bar charts** | Color-coded bars — 🟡 comparing, 🔴 swapping, 🟣 merging, 🟢 sorted |
| **Step counters** | Comparisons, swaps/writes, and % progress per algorithm |
| **Speed control** | 5 speeds from "Very Slow" (easy to follow) to "Blazing" |
| **Array size** | 20 / 40 / 60 / 80 elements |
| **Complexity table** | Best/avg/worst case, space, stability for all three |

**Key takeaway you'll see live:** Bubble Sort's comparison and swap counters explode compared to Merge Sort and Quick Sort — especially as array size grows. At n=80, Bubble Sort performs thousands more comparisons than its O(n log n) rivals.

