    name: 'Heap Sort',
    badge: 'Fast',
    badgeClass: 'badge-fast',
    color: '#ffd93d',
    complexity: {
      best: 'O(n log n)', avg: 'O(n log n)', worst: 'O(n log n)', space: 'O(1)'
    },
    desc: 'Uses a max-heap. Guaranteed O(n log n) with O(1) space. No worst-case pitfall.'
  }
];

// ─── State ────────────────────────────────────────────────────────────────────
let originalArray = [];
let algoStates = {};
let animFrames = {};
let running = false;
let finished = 0;

// ─── DOM Helpers ──────────────────────────────────────────────────────────────
function $(id) { return document.getElementById(id); }

function getSize()  { return parseInt($('sizeSlider').value); }
function getDelay() {
  const v = parseInt($('speedSlider').value);
  return [0, 80, 35, 15, 5, 1][v];
}

// ─── Build UI ─────────────────────────────────────────────────────────────────
function buildPanels() {
  const container = $('panels');
  container.innerHTML = '';
  ALGOS.forEach(algo => {
    const div = document.createElement('div');
    div.className = 'panel';
    div.id = 'panel-' + algo.id;
    div.innerHTML = `
      <div class="panel-header">
        <div class="algo-name" style="color:${algo.color}">${algo.name}</div>
        <span class="badge ${algo.badgeClass}">${algo.badge}</span>
      </div>
      <div class="complexity">
        ${algo.desc}<br/>
        <span>Best:</span> ${algo.complexity.best} &nbsp;
        <span>Avg:</span> ${algo.complexity.avg} &nbsp;
        <span>Worst:</span> ${algo.complexity.worst} &nbsp;
        <span>Space:</span> ${algo.complexity.space}
      </div>
      <div class="stats">
        <div class="stat-box">
          <div class="stat-val" id="cmp-${algo.id}">0</div>
          <div class="stat-lbl">Comparisons</div>
        </div>
        <div class="stat-box">
          <div class="stat-val" id="swp-${algo.id}">0</div>
