// ─── Array Generation ─────────────────────────────────────────────────────────
function randomArray(n) {
  return Array.from({length: n}, () => Math.floor(Math.random() * 95) + 5);
}

function resetAll() {
  if (running) return;
  const n = getSize();
  originalArray = randomArray(n);
  algoStates = {};
  ALGOS.forEach(algo => {
    algoStates[algo.id] = {
