// ─── Drawing ──────────────────────────────────────────────────────────────────
function drawBars(algoId) {
  const canvas = $('canvas-' + algoId);
  if (!canvas) return;
  const wrap = canvas.parentElement;
  canvas.width  = wrap.clientWidth  || 300;
  canvas.height = wrap.clientHeight || 160;
  const ctx = canvas.getContext('2d');
  const state = algoStates[algoId];
  if (!state) return;
  const arr = state.arr;
  const n = arr.length;
  const W = canvas.width;
  const H = canvas.height;
  const barW = W / n;
  const maxVal = 100;

  ctx.clearRect(0, 0, W, H);

  const algo = ALGOS.find(a => a.id === algoId);

  for (let i = 0; i < n; i++) {
    const h = (arr[i] / maxVal) * (H - 4);
    const x = i * barW;
    const y = H - h;

    let color = algo.color;
    if (state.highlights[i] === 'compare') color = '#ffffff';
    else if (state.highlights[i] === 'swap')    color = '#ff6b6b';
    else if (state.highlights[i] === 'sorted')  color = '#6bcb7788';
    else if (state.highlights[i] === 'pivot')   color = '#ffd93d';

    ctx.fillStyle = color;
    ctx.fillRect(x + 0.5, y, Math.max(barW - 1, 1), h);
  }
}

// ─── Stat Updates ─────────────────────────────────────────────────────────────
function updateStats(id) {
  const s = algoStates[id];
  $('cmp-' + id).textContent = s.comparisons.toLocaleString();
  $('swp-' + id).textContent = s.swaps.toLocaleString();
  if (s.startTime) {
    const t = (s.endTime || Date.now()) - s.startTime;
    $('time-' + id).textContent = t + 'ms';
  }
}

// ─── Algorithm Step Generators ────────────────────────────────────────────────

// BUBBLE SORT
function* bubbleSortGen(state) {
  const arr = state.arr;
  const n = arr.length;
  for (let i = 0; i < n - 1; i++) {
    let swapped = false;
    for (let j = 0; j < n - i - 1; j++) {
      state.highlights = { [j]: 'compare', [j+1]: 'compare' };
      state.comparisons++;
      yield;
      if (arr[j] > arr[j+1]) {
        [arr[j], arr[j+1]] = [arr[j+1], arr[j]];
        state.swaps++;
        state.highlights = { [j]: 'swap', [j+1]: 'swap' };
        swapped = true;
        yield;
      }
    }
    state.highlights[n - i - 1] = 'sorted';
    if (!swapped) break;
  }
  state.highlights = {};
  for (let k = 0; k < n; k++) state.highlights[k] = 'sorted';
}

// MERGE SORT
function* mergeSortGen(state) {
  const arr = state.arr;

  function* mergeSort(l, r) {
    if (r - l <= 1) return;
    const m = Math.floor((l + r) / 2);
    yield* mergeSort(l, m);
    yield* mergeSort(m, r);
    yield* merge(l, m, r);
  }

  function* merge(l, m, r) {
    const left  = arr.slice(l, m);
    const right = arr.slice(m, r);
    let i = 0, j = 0, k = l;
    while (i < left.length && j < right.length) {
      state.highlights = { [l+i]: 'compare', [m+j]: 'compare' };
      state.comparisons++;
      yield;
      if (left[i] <= right[j]) {
        arr[k++] = left[i++];
      } else {
        arr[k++] = right[j++];
      }
      state.swaps++;
      state.highlights[k-1] = 'swap';
      yield;
    }
    while (i < left.length) { arr[k++] = left[i++]; state.swaps++; }
    while (j < right.length) { arr[k++] = right[j++]; state.swaps++; }
    for (let x = l; x < r; x++) state.highlights[x] = 'sorted';
    yield;
  }

  yield* mergeSort(0, arr.length);
  state.highlights = {};
  for (let k = 0; k < arr.length; k++) state.highlights[k] = 'sorted';
}

// QUICK SORT
function* quickSortGen(state) {
  const arr = state.arr;

  function* quickSort(lo, hi) {
    if (lo >= hi) return;
    // Median-of-three pivot
    const mid = Math.floor((lo + hi) / 2);
    if (arr[mid] < arr[lo]) [arr[lo], arr[mid]] = [arr[mid], arr[lo]];
    if (arr[hi]  < arr[lo]) [arr[lo], arr[hi]]  = [arr[hi],  arr[lo]];
    if (arr[mid] < arr[hi]) [arr[mid], arr[hi]] = [arr[hi],  arr[mid]];
    const pivot = arr[hi];
    state.highlights[hi] = 'pivot';
    let i = lo - 1;
    for (let j = lo; j < hi; j++) {
      state.highlights[j] = 'compare';
      state.comparisons++;
      yield;
      if (arr[j] <= pivot) {
        i++;
        [arr[i], arr[j]] = [arr[j], arr[i]];
        state.swaps++;
        state.highlights[i] = 'swap';
        state.highlights[j] = 'swap';
        yield;
      }
      if (state.highlights[j] !== 'sorted') delete state.highlights[j];
    }
    [arr[i+1], arr[hi]] = [arr[hi], arr[i+1]];
    state.swaps++;
    state.highlights[i+1] = 'sorted';
    yield;
    yield* quickSort(lo, i);
    yield* quickSort(i + 2, hi);
  }

  yield* quickSort(0, arr.length - 1);
  state.highlights = {};
  for (let k = 0; k < arr.length; k++) state.highlights[k] = 'sorted';
}

// HEAP SORT
function* heapSortGen(state) {
  const arr = state.arr;
  const n = arr.length;

  function* heapify(size, root) {
    let largest = root;
    const l = 2 * root + 1;
    const r = 2 * root + 2;
    state.highlights = { [root]: 'compare' };
    if (l < size) {
      state.highlights[l] = 'compare';
      state.comparisons++;
      yield;
      if (arr[l] > arr[largest]) largest = l;
    }
    if (r < size) {
      state.highlights[r] = 'compare';
      state.comparisons++;
      yield;
      if (arr[r] > arr[largest]) largest = r;
    }
    if (largest !== root) {
      [arr[root], arr[largest]] = [arr[largest], arr[root]];
      state.swaps++;
      state.highlights = { [root]: 'swap', [largest]: 'swap' };
      yield;
      yield* heapify(size, largest);
    }
  }

  for (let i = Math.floor(n / 2) - 1; i >= 0; i--) {
    yield* heapify(n, i);
  }

  for (let i = n - 1; i > 0; i--) {
    [arr[0], arr[i]] = [arr[i], arr[0]];
    state.swaps++;
    state.highlights = { 0: 'swap', [i]: 'sorted' };
    yield;
    yield* heapify(i, 0);
  }

  state.highlights = {};
  for (let k = 0; k < n; k++) state.highlights[k] = 'sorted';
}

const GENERATORS = {
  bubble: bubbleSortGen,
  merge:  mergeSortGen,
  quick:  quickSortGen,
  heap:   heapSortGen
};

// ─── Animation Loop ───────────────────────────────────────────────────────────
function runAlgo(algoId) {
  const state = algoStates[algoId];
  state.startTime = Date.now();
  $('status-' + algoId).textContent = 'Sorting…';

  const gen = GENERATORS[algoId](state);
  const delay = getDelay();

  function step() {
    const result = gen.next();
    drawBars(algoId);
    updateStats(algoId);

    if (!result.done) {
      if (delay === 0) {
        // Run many steps per frame for max speed
        let count = 0;
        while (count++ < 50) {
          const r2 = gen.next();
          if (r2.done) {
            finishAlgo(algoId);
            return;
          }
        }
        animFrames[algoId] = requestAnimationFrame(step);
      } else {
        animFrames[algoId] = setTimeout(step, delay);
      }
    } else {
      finishAlgo(algoId);
    }
  }

  animFrames[algoId] = delay === 0 ? requestAnimationFrame(step) : setTimeout(step, delay);
}

function finishAlgo(algoId) {
  const state = algoStates[algoId];
  state.done = true;
  state.endTime = Date.now();
  drawBars(algoId);
  updateStats(algoId);
  const st = $('status-' + algoId);
  const ms = state.endTime - state.startTime;
  st.textContent = `✅ Done in ${ms}ms`;
  st.className = 'status-text status-done';
  finished++;
  if (finished === ALGOS.length) {
    running = false;
    $('btnSort').disabled  = false;
    $('btnReset').disabled = false;
    $('sizeSlider').disabled  = false;
    $('speedSlider').disabled = false;
  }
}

// ─── Start Race ───────────────────────────────────────────────────────────────
function startRace() {
  if (running) return;
  running = true;
  finished = 0;
  $('btnSort').disabled  = true;
  $('btnReset').disabled = true;
  $('sizeSlider').disabled  = true;
  $('speedSlider').disabled = true;

  ALGOS.forEach(algo => runAlgo(algo.id));
}

// ─── Events ───────────────────────────────────────────────────────────────────
$('sizeSlider').addEventListener('input', () => {
  $('sizeVal').textContent = $('sizeSlider').value;
  if (!running) resetAll();
});

$('speedSlider').addEventListener('input', () => {
  const labels = ['', 'Slowest', 'Slow', 'Medium', 'Fast', 'Fastest'];
  $('speedVal').textContent = labels[$('speedSlider').value];
});

$('btnReset').addEventListener('click', resetAll);
$('btnSort').addEventListener('click', startRace);

window.addEventListener('resize', () => {
  ALGOS.forEach(a => drawBars(a.id));
});

// ─── Init ─────────────────────────────────────────────────────────────────────
buildPanels();
resetAll();
</script>
</body>
</html>
```

## What this demo includes:

**🎯 Four algorithms racing side-by-side:**
- **Bubble Sort** — the accused "best" algorithm
- **Merge Sort** — guaranteed O(n log n), always
- **Quick Sort** — fastest in practice, median-of-three pivot
- **Heap Sort** — O(n log n) worst case with O(1) space

**📊 Visual features:**
- Animated bar charts with color-coded highlights (white = comparing, red = swapping, yellow = pivot, green = sorted)
- Live **comparison counter**, **swap/write counter**, and **elapsed time** per algorithm
- Adjustable **array size** (10–80 elements) and **animation speed** (Slowest → Fastest)
- Complexity reference table and a plain-English verdict

**The proof:** Watch Bubble Sort still churning while the others have long since finished — especially dramatic at larger array sizes!

