      complexity: { best: 'O(n)', avg: 'O(n²)', worst: 'O(n²)', space: 'O(1)' },
      description: 'Builds sorted portion one element at a time'
    },
    {
      id: 'merge',
      name: 'Merge Sort',
      color: '#6bcb77',
      badge: 'O(n log n)',
      badgeClass: 'badge-good',
      complexity: { best: 'O(n log n)', avg: 'O(n log n)', worst: 'O(n log n)', space: 'O(n)' },
      description: 'Divide and conquer recursive splitting'
    },
    {
      id: 'quick',
      name: 'Quick Sort',
      color: '#4d96ff',
      badge: 'O(n log n) avg',
      badgeClass: 'badge-great',
      complexity: { best: 'O(n log n)', avg: 'O(n log n)', worst: 'O(n²)', space: 'O(log n)' },
      description: 'Pivot-based partitioning'
    }
  ];

  // ─── State ───────────────────────────────────────────────────────────────────
  let baseArray = [];
  let runners   = {};   // id → { array, steps, swaps, comparisons, done, highlights }
  let animFrames = {};  // id → requestAnimationFrame handle
  let generators = {};  // id → generator
  let running    = false;
  let allDone    = false;

  // ─── DOM helpers ─────────────────────────────────────────────────────────────
  const sizeSlider  = document.getElementById('sizeSlider');
  const speedSlider = document.getElementById('speedSlider');
  const sizeVal     = document.getElementById('sizeVal');
  const speedVal    = document.getElementById('speedVal');
  const btnGenerate = document.getElementById('btnGenerate');
  const btnStart    = document.getElementById('btnStart');
  const btnReset    = document.getElementById('btnReset');
  const panelsEl    = document.getElementById('panels');
  const winnerBanner = document.getElementById('winnerBanner');

  sizeSlider.addEventListener('input', () => { sizeVal.textContent = sizeSlider.value; });
  speedSlider.addEventListener('input', () => { speedVal.textContent = speedSlider.value; });

  // ─── Array generation ────────────────────────────────────────────────────────
  function generateArray(n) {
    const arr = [];
    for (let i = 0; i < n; i++) arr.push(Math.floor(Math.random() * 95) + 5);
    return arr;
  }

  // ─── Build UI ────────────────────────────────────────────────────────────────
  function buildPanels() {
    panelsEl.innerHTML = '';
    ALGORITHMS.forEach(algo => {
      const panel = document.createElement('div');
      panel.className = 'panel';
      panel.id = `panel-${algo.id}`;
      panel.innerHTML = `
        <div class="panel-header">
          <div>
            <div class="algo-name" style="color:${algo.color}">${algo.name}</div>
            <div style="font-size:0.75rem;color:#666;margin-top:2px">${algo.description}</div>
          </div>
