        </div>
        <div class="complexity">
          Best: <span>${algo.complexity.best}</span> &nbsp;|&nbsp;
          Avg: <span>${algo.complexity.avg}</span> &nbsp;|&nbsp;
          Worst: <span>${algo.complexity.worst}</span> &nbsp;|&nbsp;
