          <div class="stat-box">
            <div class="stat-val" id="steps-${algo.id}">0</div>
            <div class="stat-lbl">Steps</div>
          </div>
          <div class="stat-box">
            <div class="stat-val" id="comps-${algo.id}">0</div>
            <div class="stat-lbl">Comparisons</div>
          </div>
          <div class="stat-box">
            <div class="stat-val" id="swaps-${algo.id}">0</div>
            <div class="stat-lbl">Swaps</div>
          </div>
        </div>
        <div class="status-line" id="status-${algo.id}">Ready</div>
        <div class="chart-wrap">
          <canvas id="canvas-${algo.id}"></canvas>
        </div>
      `;
      panelsEl.appendChild(panel);
    });
  }

  // ─── Canvas drawing ──────────────────────────────────────────────────────────
  function drawBars(algoId) {
    const canvas = document.getElementById(`canvas-${algoId}`);
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const wrap = canvas.parentElement;
    canvas.width  = wrap.clientWidth;
    canvas.height = wrap.clientHeight;

    const r = runners[algoId];
    if (!r) return;

    const arr = r.array;
    const n   = arr.length;
    const W   = canvas.width;
    const H   = canvas.height;
    const barW = W / n;
    const maxVal = 100;
    const algo = ALGORITHMS.find(a => a.id === algoId);

    ctx.clearRect(0, 0, W, H);

    for (let i = 0; i < n; i++) {
      const barH = (arr[i] / maxVal) * (H - 4);
      const x    = i * barW;
      const y    = H - barH;

      let color = algo.color + 'bb';

      if (r.done) {
        color = algo.color;
      } else if (r.highlights) {
        if (r.highlights.sorted && r.highlights.sorted.includes(i)) {
          color = algo.color;
        } else if (r.highlights.active && r.highlights.active.includes(i)) {
          color = '#ffffff';
        } else if (r.highlights.comparing && r.highlights.comparing.includes(i)) {
          color = '#ffffffaa';
        }
      }

      ctx.fillStyle = color;
      const gap = barW > 3 ? 1 : 0;
      ctx.beginPath();
      ctx.roundRect
        ? ctx.roundRect(x + gap, y, barW - gap * 2, barH, barW > 6 ? 2 : 0)
        : ctx.rect(x + gap, y, barW - gap * 2, barH);
      ctx.fill();
    }
  }

  function updateStats(id) {
    const r = runners[id];
    if (!r) return;
    document.getElementById(`steps-${id}`).textContent = r.steps.toLocaleString();
    document.getElementById(`comps-${id}`).textContent = r.comparisons.toLocaleString();
    document.getElementById(`swaps-${id}`).textContent = r.swaps.toLocaleString();
  }

  function setStatus(id, msg) {
    const el = document.getElementById(`status-${id}`);
    if (el) el.textContent = msg;
  }

  // ─── Sorting Generators ───────────────────────────────────────────────────────

  // Bubble Sort
  function* bubbleSortGen(r) {
    const arr = r.array;
    const n   = arr.length;
    let sorted = [];
    for (let i = 0; i < n - 1; i++) {
      let swapped = false;
      for (let j = 0; j < n - i - 1; j++) {
        r.steps++; r.comparisons++;
        r.highlights = { comparing: [j, j+1], sorted };
        yield;
        if (arr[j] > arr[j+1]) {
          [arr[j], arr[j+1]] = [arr[j+1], arr[j]];
          r.swaps++;
          r.highlights = { active: [j, j+1], sorted };
          yield;
          swapped = true;
        }
      }
      sorted = [...sorted, n - i - 1];
      r.highlights = { sorted };
      if (!swapped) break;
    }
    r.highlights = { sorted: arr.map((_, i) => i) };
    r.done = true;
  }

  // Insertion Sort
  function* insertionSortGen(r) {
    const arr = r.array;
    const n   = arr.length;
    let sorted = [0];
    for (let i = 1; i < n; i++) {
      let key = arr[i];
      let j   = i - 1;
      r.steps++;
      r.highlights = { active: [i], sorted };
      yield;
      while (j >= 0 && arr[j] > key) {
        r.steps++; r.comparisons++;
        arr[j+1] = arr[j];
        r.swaps++;
        r.highlights = { active: [j, j+1], sorted };
        yield;
        j--;
      }
      r.comparisons++;
      arr[j+1] = key;
      sorted = [...sorted, i];
      r.highlights = { sorted, active: [j+1] };
      yield;
    }
    r.highlights = { sorted: arr.map((_, i) => i) };
    r.done = true;
  }

  // Merge Sort
  function* mergeSortGen(r) {
    const arr = r.array;

    function* mergeSort(left, right) {
      if (right - left <= 1) return;
      const mid = Math.floor((left + right) / 2);
      yield* mergeSort(left, mid);
      yield* mergeSort(mid, right);
      yield* merge(left, mid, right);
    }

    function* merge(left, mid, right) {
      const leftArr  = arr.slice(left, mid);
      const rightArr = arr.slice(mid, right);
      let i = 0, j = 0, k = left;
      while (i < leftArr.length && j < rightArr.length) {
        r.steps++; r.comparisons++;
        r.highlights = { comparing: [left + i, mid + j] };
        yield;
        if (leftArr[i] <= rightArr[j]) {
          arr[k++] = leftArr[i++];
        } else {
          arr[k++] = rightArr[j++];
          r.swaps++;
        }
        r.highlights = { active: [k-1] };
        yield;
      }
      while (i < leftArr.length) { arr[k++] = leftArr[i++]; r.steps++; yield; }
      while (j < rightArr.length) { arr[k++] = rightArr[j++]; r.steps++; yield; }
    }

    yield* mergeSort(0, arr.length);
    r.highlights = { sorted: arr.map((_, i) => i) };
    r.done = true;
  }

  // Quick Sort
  function* quickSortGen(r) {
    const arr = r.array;

    function* quickSort(low, high) {
      if (low < high) {
        let pivotIdx;
        [pivotIdx] = yield* partition(low, high);
        yield* quickSort(low, pivotIdx - 1);
        yield* quickSort(pivotIdx + 1, high);
      }
    }

    function* partition(low, high) {
      const pivot = arr[high];
      let i = low - 1;
      r.highlights = { active: [high] };
      yield;
      for (let j = low; j < high; j++) {
        r.steps++; r.comparisons++;
        r.highlights = { comparing: [j, high], active: [high] };
        yield;
        if (arr[j] <= pivot) {
          i++;
          [arr[i], arr[j]] = [arr[j], arr[i]];
          r.swaps++;
          r.highlights = { active: [i, j, high] };
          yield;
        }
      }
      [arr[i+1], arr[high]] = [arr[high], arr[i+1]];
      r.swaps++;
      r.highlights = { active: [i+1] };
      yield;
      return [i + 1];
    }

    yield* quickSort(0, arr.length - 1);
    r.highlights = { sorted: arr.map((_, i) => i) };
    r.done = true;
  }

  const GEN_MAP = {
    bubble:    bubbleSortGen,
    insertion: insertionSortGen,
    merge:     mergeSortGen,
    quick:     quickSortGen
  };

  // ─── Animation loop ──────────────────────────────────────────────────────────
  function getDelay() {
    const speed = parseInt(speedSlider.value);
    // speed 1 = slow (80ms), speed 10 = fast (1ms)
    return Math.max(1, 85 - speed * 8);
  }

  function getStepsPerFrame() {
    const speed = parseInt(speedSlider.value);
    if (speed <= 3) return 1;
    if (speed <= 6) return 2;
    if (speed <= 8) return 4;
    return 8;
  }

  function runAlgo(id) {
    const gen = generators[id];
    const r   = runners[id];
    if (!gen || !r || r.done) return;

    const spf = getStepsPerFrame();
    for (let s = 0; s < spf; s++) {
      const result = gen.next();
      if (result.done) {
        r.done = true;
        break;
      }
    }

    updateStats(id);
    drawBars(id);

    if (r.done) {
      setStatus(id, `✅ Done! ${r.steps.toLocaleString()} steps`);
      checkAllDone();
      return;
    }

    animFrames[id] = setTimeout(() => runAlgo(id), getDelay());
  }

  function checkAllDone() {
    const done = ALGORITHMS.every(a => runners[a.id] && runners[a.id].done);
    if (done && !allDone) {
      allDone = true;
      running = false;
      btnStart.disabled   = false;
      btnGenerate.disabled = false;
      btnReset.disabled   = false;
      winnerBanner.style.display = 'block';
    }
  }

  // ─── Controls ────────────────────────────────────────────────────────────────
  function initRunners() {
    runners = {};
    ALGORITHMS.forEach(algo => {
      runners[algo.id] = {
        array:       [...baseArray],
        steps:       0,
        comparisons: 0,
        swaps:       0,
        done:        false,
        highlights:  {}
      };
    });
  }

  function generateNew() {
    stopAll();
    winnerBanner.style.display = 'none';
    allDone = false;
    const n = parseInt(sizeSlider.value);
    baseArray = generateArray(n);
    initRunners();
    ALGORITHMS.forEach(a => {
      updateStats(a.id);
      setStatus(a.id, 'Ready');
      drawBars(a.id);
    });
    btnStart.disabled    = false;
    btnReset.disabled    = true;
    btnGenerate.disabled = false;
  }

  function stopAll() {
    ALGORITHMS.forEach(a => {
      if (animFrames[a.id]) {
        clearTimeout(animFrames[a.id]);
        animFrames[a.id] = null;
      }
    });
    running = false;
  }

  function startSort() {
    if (running) return;
    running = true;
    allDone = false;
    winnerBanner.style.display = 'none';
    btnStart.disabled    = true;
    btnGenerate.disabled = true;
    btnReset.disabled    = false;

    ALGORITHMS.forEach(a => {
      if (!runners[a.id].done) {
        generators[a.id] = GEN_MAP[a.id](runners[a.id]);
        setStatus(a.id, 'Sorting…');
        runAlgo(a.id);
      }
    });
  }

  function resetAll() {
    stopAll();
    winnerBanner.style.display = 'none';
    allDone = false;
    initRunners();
    generators = {};
    ALGORITHMS.forEach(a => {
      updateStats(a.id);
      setStatus(a.id, 'Ready');
      drawBars(a.id);
    });
    btnStart.disabled    = false;
    btnReset.disabled    = true;
    btnGenerate.disabled = false;
  }

  btnGenerate.addEventListener('click', generateNew);
  btnStart.addEventListener('click', startSort);
  btnReset.addEventListener('click', resetAll);

  // ─── Resize handling ─────────────────────────────────────────────────────────
  window.addEventListener('resize', () => {
    ALGORITHMS.forEach(a => drawBars(a.id));
  });

  // ─── Init ─────────────────────────────────────────────────────────────────────
  buildPanels();
  generateNew();
</script>
</body>
</html>
```

---

### What this demo does:

| Feature | Details |
|---|---|
| **4 algorithms** | Bubble, Insertion, Merge, and Quick Sort |
| **Side-by-side animation** | All run simultaneously on the **same randomized data** |
| **Live counters** | Steps, Comparisons, and Swaps update in real time |
| **Visual highlights** | White = active bars, colored = sorted portion |
| **Controls** | Array size (10–120), speed slider, Generate/Sort/Reset buttons |
| **Complexity cards** | Big-O breakdown for all 4 algorithms with a verdict |

**Key takeaway you'll see instantly:** Bubble Sort's bar chart churns away long after Merge and Quick Sort have finished — the step counter tells the whole story. 🏆

