      <div class="complexity">Time: O(n log n) avg, O(n²) worst &nbsp;|&nbsp; Space: O(log n)</div>
      <div class="stats">
        <div class="stat"><span class="stat-val comparisons" id="q-cmp">0</span><span class="stat-label">Comparisons</span></div>
        <div class="stat"><span class="stat-val swaps" id="q-swp">0</span><span class="stat-label">Swaps</span></div>
        <div class="stat"><span class="stat-val time" id="q-time">—</span><span class="stat-label">Steps</span></div>
      </div>
    </div>
    <div class="chart-wrap" id="chart-quick"></div>
    <div class="status-bar"><div class="status-dot dot-idle" id="dot-quick"></div><span id="status-quick">Waiting…</span></div>
  </div>
