<script>
// ─── Globals ────────────────────────────────────────────────────────────────
let masterArray = [];
let running = false;
let animFrames = { bubble: null, merge: null, quick: null };

const speedMap = { 1: 0, 2: 2, 3: 8, 4: 20, 5: 40 };
const speedNames = { 1: 'Ludicrous', 2: 'Fast', 3: 'Normal', 4: 'Slow', 5: 'Turtle' };

function getDelay() {
  const s = +document.getElementById('speedSlider').value;
  return speedMap[s];
}

// ─── Array Generation ───────────────────────────────────────────────────────
function generateArray() {
  const n = +document.getElementById('sizeSlider').value;
  const type = document.getElementById('inputType').value;
  let arr = Array.from({ length: n }, (_, i) => Math.floor((i + 1) * (100 / n)));

  if (type === 'random') {
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
  } else if (type === 'nearly') {
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    // sort then displace a few
    arr.sort((a, b) => a - b);
    const swaps = Math.floor(n * 0.05);
    for (let k = 0; k < swaps; k++) {
      const i = Math.floor(Math.random() * n);
      const j = Math.floor(Math.random() * n);
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
  } else if (type === 'reversed') {
    arr.sort((a, b) => b - a);
  } else if (type === 'equal') {
    const vals = [20, 40, 60, 80, 100];
    arr = Array.from({ length: n }, () => vals[Math.floor(Math.random() * vals.length)]);
  }
  return arr;
}

// ─── Bar Rendering ──────────────────────────────────────────────────────────
function initBars(containerId, arr) {
  const container = document.getElementById(containerId);
  container.innerHTML = '';
  const maxVal = Math.max(...arr);
  arr.forEach(v => {
    const bar = document.createElement('div');
    bar.className = 'bar';
    bar.style.height = (v / maxVal * 100) + '%';
    bar.style.background = '#4fc3f7';
    container.appendChild(bar);
  });
}

function updateBars(containerId, arr, highlights = {}, sorted = new Set()) {
  const container = document.getElementById(containerId);
  const bars = container.children;
  const maxVal = Math.max(...arr);
  for (let i = 0; i < arr.length; i++) {
    bars[i].style.height = (arr[i] / maxVal * 100) + '%';
    if (sorted.has(i))          bars[i].style.background = '#00c853';
    else if (highlights[i] === 'swap')    bars[i].style.background = '#ff4d4d';
    else if (highlights[i] === 'compare') bars[i].style.background = '#ffd700';
    else if (highlights[i] === 'pivot')   bars[i].style.background = '#ff9800';
    else                                  bars[i].style.background = '#4fc3f7';
  }
}

function markAllSorted(containerId) {
  const bars = document.getElementById(containerId).children;
  for (let b of bars) b.style.background = '#00c853';
}

// ─── UI Helpers ─────────────────────────────────────────────────────────────
function setStatus(algo, msg, state) {
  document.getElementById(`status-${algo}`).textContent = msg;
  const dot = document.getElementById(`dot-${algo}`);
  dot.className = 'status-dot dot-' + state;
}

function setStats(prefix, cmp, swp, steps) {
  document.getElementById(`${prefix}-cmp`).textContent = cmp.toLocaleString();
  document.getElementById(`${prefix}-swp`).textContent = swp.toLocaleString();
  document.getElementById(`${prefix}-time`).textContent = steps === null ? '—' : steps.toLocaleString();
}

// ─── Sleep Helper ───────────────────────────────────────────────────────────
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// ─── BUBBLE SORT ────────────────────────────────────────────────────────────
async function bubbleSort(arr) {
  const n = arr.length;
  let cmp = 0, swp = 0, steps = 0;
  const sorted = new Set();

  setStatus('bubble', 'Sorting…', 'running');

  for (let i = 0; i < n - 1; i++) {
    let swapped = false;
    for (let j = 0; j < n - i - 1; j++) {
      if (!running) return;
      cmp++; steps++;
      const hl = { [j]: 'compare', [j+1]: 'compare' };
      updateBars('chart-bubble', arr, hl, sorted);
      setStats('b', cmp, swp, steps);

      if (arr[j] > arr[j + 1]) {
        [arr[j], arr[j+1]] = [arr[j+1], arr[j]];
        swp++; steps++;
        const hl2 = { [j]: 'swap', [j+1]: 'swap' };
        updateBars('chart-bubble', arr, hl2, sorted);
        setStats('b', cmp, swp, steps);
        swapped = true;
      }
      const d = getDelay();
      if (d > 0) await sleep(d);
    }
    sorted.add(n - 1 - i);
    updateBars('chart-bubble', arr, {}, sorted);
    if (!swapped) break;
  }
  sorted.add(0);
  markAllSorted('chart-bubble');
  setStats('b', cmp, swp, steps);
  setStatus('bubble', `Done! ${steps.toLocaleString()} steps 😵`, 'done');
  return { cmp, swp, steps };
}

// ─── MERGE SORT ─────────────────────────────────────────────────────────────
async function mergeSort(arr) {
  let cmp = 0, writes = 0, steps = 0;
  setStatus('merge', 'Sorting…', 'running');

  async function mergeSortHelper(a, left, right) {
    if (left >= right) return;
    const mid = Math.floor((left + right) / 2);
    await mergeSortHelper(a, left, mid);
    await mergeSortHelper(a, mid + 1, right);
    await merge(a, left, mid, right);
  }

  async function merge(a, left, mid, right) {
    const leftArr = a.slice(left, mid + 1);
    const rightArr = a.slice(mid + 1, right + 1);
    let i = 0, j = 0, k = left;

    while (i < leftArr.length && j < rightArr.length) {
      if (!running) return;
      cmp++; steps++;
      const hl = { [k]: 'compare' };
      updateBars('chart-merge', a, hl, new Set());
      setStats('m', cmp, writes, steps);

      if (leftArr[i] <= rightArr[j]) {
        a[k++] = leftArr[i++];
      } else {
        a[k++] = rightArr[j++];
      }
      writes++; steps++;
      updateBars('chart-merge', a, { [k-1]: 'swap' }, new Set());
      setStats('m', cmp, writes, steps);
      const d = getDelay();
      if (d > 0) await sleep(d);
    }
    while (i < leftArr.length) {
      if (!running) return;
      a[k++] = leftArr[i++];
      writes++; steps++;
      updateBars('chart-merge', a, { [k-1]: 'swap' }, new Set());
      setStats('m', cmp, writes, steps);
      const d = getDelay();
      if (d > 0) await sleep(d);
    }
    while (j < rightArr.length) {
      if (!running) return;
      a[k++] = rightArr[j++];
      writes++; steps++;
      updateBars('chart-merge', a, { [k-1]: 'swap' }, new Set());
      setStats('m', cmp, writes, steps);
      const d = getDelay();
      if (d > 0) await sleep(d);
    }
  }

  await mergeSortHelper(arr, 0, arr.length - 1);
  markAllSorted('chart-merge');
  setStats('m', cmp, writes, steps);
  setStatus('merge', `Done! ${steps.toLocaleString()} steps 🚀`, 'done');
  return { cmp, swp: writes, steps };
}

// ─── QUICK SORT ─────────────────────────────────────────────────────────────
async function quickSort(arr) {
  let cmp = 0, swp = 0, steps = 0;
  setStatus('quick', 'Sorting…', 'running');

  async function partition(a, low, high) {
    const pivot = a[high];
    let i = low - 1;

    for (let j = low; j < high; j++) {
      if (!running) return i;
      cmp++; steps++;
      const hl = { [j]: 'compare', [high]: 'pivot' };
      updateBars('chart-quick', a, hl, new Set());
      setStats('q', cmp, swp, steps);
      const d = getDelay();
      if (d > 0) await sleep(d);

      if (a[j] <= pivot) {
        i++;
        [a[i], a[j]] = [a[j], a[i]];
        swp++; steps++;
        const hl2 = { [i]: 'swap', [j]: 'swap', [high]: 'pivot' };
        updateBars('chart-quick', a, hl2, new Set());
        setStats('q', cmp, swp, steps);
        if (d > 0) await sleep(d);
      }
    }
    [a[i+1], a[high]] = [a[high], a[i+1]];
    swp++; steps++;
    return i + 1;
  }

  async function qs(a, low, high) {
    if (low < high) {
      const pi = await partition(a, low, high);
      if (!running) return;
      await qs(a, low, pi - 1);
      await qs(a, pi + 1, high);
    }
  }

  await qs(arr, 0, arr.length - 1);
  markAllSorted('chart-quick');
  setStats('q', cmp, swp, steps);
  setStatus('quick', `Done! ${steps.toLocaleString()} steps ⚡`, 'done');
  return { cmp, swp, steps };
}

// ─── Race Coordinator ───────────────────────────────────────────────────────
async function startRace() {
  if (running) return;
  running = true;
  document.getElementById('btnStart').disabled = true;
  document.getElementById('btnReset').disabled = true;
  document.getElementById('winnerBanner').classList.remove('show');

  const arrB = [...masterArray];
  const arrM = [...masterArray];
  const arrQ = [...masterArray];

  initBars('chart-bubble', arrB);
  initBars('chart-merge',  arrM);
  initBars('chart-quick',  arrQ);

  setStats('b', 0, 0, null);
  setStats('m', 0, 0, null);
  setStats('q', 0, 0, null);

  ['bubble','merge','quick'].forEach(a => setStatus(a, 'Sorting…', 'running'));

  const results = await Promise.all([
    bubbleSort(arrB),
    mergeSort(arrM),
    quickSort(arrQ)
  ]);

  running = false;
  document.getElementById('btnStart').disabled = false;
  document.getElementById('btnReset').disabled = false;

  if (results[0] && results[1] && results[2]) {
    showVerdict(results[0], results[1], results[2]);
  }
}

function showVerdict(b, m, q) {
  const bS = b.steps, mS = m.steps, qS = q.steps;
  const bubbleVsMerge = (bS / mS).toFixed(1);
  const bubbleVsQuick = (bS / qS).toFixed(1);
  const banner = document.getElementById('winnerBanner');
  const n = masterArray.length;

  banner.innerHTML = `
    <div style="font-size:1.4rem;margin-bottom:10px">📊 Verdict</div>
    <strong>Bubble Sort</strong> needed <strong style="color:#ff4d4d">${bS.toLocaleString()} steps</strong>.<br>
    <strong>Merge Sort</strong> did it in <strong style="color:#00e5ff">${mS.toLocaleString()} steps</strong> 
    — that's <strong>${bubbleVsMerge}× fewer steps</strong>.<br>
    <strong>Quick Sort</strong> did it in <strong style="color:#69f0ae">${qS.toLocaleString()} steps</strong> 
    — that's <strong>${bubbleVsQuick}× fewer steps</strong>.<br><br>
    <span style="color:#888;font-size:0.85rem">
      With n=${n}, Bubble Sort's O(n²) ≈ ${(n*n).toLocaleString()} operations. 
      Merge/Quick Sort's O(n log n) ≈ ${Math.round(n * Math.log2(n)).toLocaleString()} operations. 
      At n=10,000 the gap becomes <strong style="color:#ffd700">~1,300×</strong>. 
      Still think Bubble Sort is best? 🤦
    </span>
  `;
  banner.classList.add('show');
}

// ─── Reset ──────────────────────────────────────────────────────────────────
function resetAll() {
  running = false;
  document.getElementById('btnStart').disabled = false;
  document.getElementById('winnerBanner').classList.remove('show');

  masterArray = generateArray();

  initBars('chart-bubble', [...masterArray]);
  initBars('chart-merge',  [...masterArray]);
  initBars('chart-quick',  [...masterArray]);

  setStats('b', 0, 0, null);
  setStats('m', 0, 0, null);
  setStats('q', 0, 0, null);

  ['bubble','merge','quick'].forEach(a => setStatus(a, 'Ready — press Start Race!', 'idle'));
}

// ─── Event Listeners ────────────────────────────────────────────────────────
document.getElementById('btnStart').addEventListener('click', startRace);
document.getElementById('btnReset').addEventListener('click', resetAll);

document.getElementById('sizeSlider').addEventListener('input', function() {
  document.getElementById('sizeLabel').textContent = this.value + ' elements';
  if (!running) resetAll();
});

document.getElementById('speedSlider').addEventListener('input', function() {
  document.getElementById('speedLabel').textContent = speedNames[this.value];
});

document.getElementById('inputType').addEventListener('change', () => {
  if (!running) resetAll();
});

// ─── Init ───────────────────────────────────────────────────────────────────
resetAll();
</script>
</body>
</html>
