<script>
// ─── State ───────────────────────────────────────────────────────────────────
let baseArray = [];
let running = false;
let animFrames = [];

const ALGOS = ['bubble', 'merge', 'quick'];

// ─── Helpers ─────────────────────────────────────────────────────────────────
function getSize() { return parseInt(document.getElementById('sizeSlider').value); }
function getDelay() { return parseInt(document.getElementById('speedSelect').value); }
function getOrder() { return document.getElementById('orderSelect').value; }

function generateArray(n, order) {
  let arr = Array.from({length: n}, (_, i) => i + 1);
  // shuffle
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  if (order === 'nearly') {
    // sort then randomly swap ~5% of elements
    arr.sort((a, b) => a - b);
    const swaps = Math.floor(n * 0.05);
    for (let k = 0; k < swaps; k++) {
      const i = Math.floor(Math.random() * n);
      const j = Math.floor(Math.random() * n);
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
  } else if (order === 'reversed') {
    arr.sort((a, b) => b - a);
  }
  return arr;
}

function getBarColor(state) {
  switch(state) {
    case 'compare': return '#ff4444';
    case 'swap':    return '#ff9900';
    case 'sorted':  return '#44ff88';
    case 'pivot':   return '#aa44ff';
    default:        return '#4488ff';
  }
}

// ─── Chart Rendering ─────────────────────────────────────────────────────────
function initChart(id, arr) {
  const container = document.getElementById(id + '-chart');
  container.innerHTML = '';
  const n = arr.length;
  const maxVal = Math.max(...arr);
  for (let i = 0; i < n; i++) {
