    bar.className = 'bar';
    bar.style.height = ((arr[i] / maxVal) * 100) + '%';
    bar.style.background = '#4488ff';
    container.appendChild(bar);
  }
}

function updateChart(id, arr, highlights = {}) {
  const container = document.getElementById(id + '-chart');
  const bars = container.children;
  const maxVal = Math.max(...arr);
  for (let i = 0; i < arr.length; i++) {
    bars[i].style.height = ((arr[i] / maxVal) * 100) + '%';
    bars[i].style.background = getBarColor(highlights[i] || 'default');
  }
}

function markAllSorted(id, arr) {
  const container = document.getElementById(id + '-chart');
  const bars = container.children;
  const maxVal = Math.max(...arr);
  for (let i = 0; i < arr.length; i++) {
    bars[i].style.height = ((arr[i] / maxVal) * 100) + '%';
    bars[i].style.background = '#44ff88';
  }
}

function setStatus(id, state, text) {
  const dot = document.getElementById(id + '-dot');
  const statusText = document.getElementById(id + '-status-text');
  dot.className = 'status-dot ' + (state === 'running' ? 'dot-running' : state === 'done' ? 'dot-done' : 'dot-idle');
  statusText.textContent = text;
}

function updateStats(id, cmp, swp, steps) {
  document.getElementById(id + '-cmp').textContent = cmp.toLocaleString();
  document.getElementById(id + '-swp').textContent = swp.toLocaleString();
  document.getElementById(id + '-steps').textContent = steps.toLocaleString();
}

// ─── Step Generators ─────────────────────────────────────────────────────────

function* bubbleSortGen(arr) {
  const n = arr.length;
  let cmp = 0, swp = 0, steps = 0;
  for (let i = 0; i < n - 1; i++) {
    let swapped = false;
    for (let j = 0; j < n - i - 1; j++) {
      cmp++;
      yield { arr: [...arr], highlights: {[j]: 'compare', [j+1]: 'compare'}, cmp, swp, steps: ++steps };
      if (arr[j] > arr[j + 1]) {
        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
        swp++; swapped = true;
        yield { arr: [...arr], highlights: {[j]: 'swap', [j+1]: 'swap'}, cmp, swp, steps: ++steps };
      }
    }
    // mark last sorted element
    const sortedHighlights = {};
    for (let k = n - i - 1; k < n; k++) sortedHighlights[k] = 'sorted';
    yield { arr: [...arr], highlights: sortedHighlights, cmp, swp, steps: ++steps };
    if (!swapped) break;
  }
  yield { arr: [...arr], highlights: {}, cmp, swp, steps, done: true };
}

function* mergeSortGen(arr) {
  let cmp = 0, swp = 0, steps = 0;

  function* mergeGen(arr, l, r) {
    if (r - l <= 1) return;
    const m = Math.floor((l + r) / 2);
    yield* mergeGen(arr, l, m);
    yield* mergeGen(arr, m, r);

    const left = arr.slice(l, m);
    const right = arr.slice(m, r);
    let i = 0, j = 0, k = l;

    while (i < left.length && j < right.length) {
      cmp++;
      const hi = {};
      hi[l + i] = 'compare';
      hi[m + j] = 'compare';
      yield { arr: [...arr], highlights: hi, cmp, swp, steps: ++steps };

      if (left[i] <= right[j]) {
        arr[k++] = left[i++];
      } else {
        arr[k++] = right[j++];
        swp++;
      }
      yield { arr: [...arr], highlights: {[k-1]: 'swap'}, cmp, swp, steps: ++steps };
    }
    while (i < left.length) { arr[k++] = left[i++]; }
    while (j < right.length) { arr[k++] = right[j++]; }

    const sortedHi = {};
    for (let x = l; x < r; x++) sortedHi[x] = 'sorted';
    yield { arr: [...arr], highlights: sortedHi, cmp, swp, steps: ++steps };
  }

  yield* mergeGen(arr, 0, arr.length);
  yield { arr: [...arr], highlights: {}, cmp, swp, steps, done: true };
}

function* quickSortGen(arr) {
  let cmp = 0, swp = 0, steps = 0;

  function* partitionGen(arr, low, high) {
    const pivot = arr[high];
    let i = low - 1;

    for (let j = low; j < high; j++) {
      cmp++;
      const hi = {};
      hi[high] = 'pivot';
      hi[j] = 'compare';
      if (i >= low) hi[i] = 'swap';
      yield { arr: [...arr], highlights: hi, cmp, swp, steps: ++steps };

      if (arr[j] <= pivot) {
        i++;
        [arr[i], arr[j]] = [arr[j], arr[i]];
        swp++;
        const hi2 = {};
        hi2[high] = 'pivot';
        hi2[i] = 'swap';
        hi2[j] = 'swap';
        yield { arr: [...arr], highlights: hi2, cmp, swp, steps: ++steps };
      }
    }
    [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
    swp++;
    yield { arr: [...arr], highlights: {[i+1]: 'sorted'}, cmp, swp, steps: ++steps };
    return i + 1;
  }

  function* quickGen(arr, low, high) {
    if (low < high) {
      let pi;
      const gen = partitionGen(arr, low, high);
      while (true) {
        const result = gen.next();
        if (result.done) { pi = result.value; break; }
        yield result.value;
      }
      // Hack: we need the return value, so let's redo with a wrapper
    }
  }

  // Iterative quick sort to properly get pivot index
  function* quickSortIterative(arr) {
    const stack = [[0, arr.length - 1]];

    function* partition(low, high) {
      const pivot = arr[high];
      let i = low - 1;
      for (let j = low; j < high; j++) {
        cmp++;
        const hi = { [high]: 'pivot', [j]: 'compare' };
        yield { arr: [...arr], highlights: hi, cmp, swp, steps: ++steps };
        if (arr[j] <= pivot) {
          i++;
          [arr[i], arr[j]] = [arr[j], arr[i]];
          swp++;
          yield { arr: [...arr], highlights: { [high]: 'pivot', [i]: 'swap', [j]: 'swap' }, cmp, swp, steps: ++steps };
        }
      }
      [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
      swp++;
      yield { arr: [...arr], highlights: { [i+1]: 'sorted' }, cmp, swp, steps: ++steps };
      return i + 1;
    }

    while (stack.length) {
      const [low, high] = stack.pop();
      if (low >= high) continue;

      // Run partition generator and capture return
      const partGen = partition(low, high);
      let pi;
      while (true) {
        const r = partGen.next();
        if (r.done) { pi = r.value; break; }
        yield r.value;
      }

      stack.push([low, pi - 1]);
      stack.push([pi + 1, high]);
    }
  }

  yield* quickSortIterative(arr);
  yield { arr: [...arr], highlights: {}, cmp, swp, steps, done: true };
}

// ─── Animation Runner ─────────────────────────────────────────────────────────
function runAlgo(id, gen, onDone) {
  setStatus(id, 'running', 'Sorting...');
  let lastStep = null;

  function tick() {
    const delay = getDelay();
    const result = gen.next();
    if (result.done || result.value === undefined) {
      if (lastStep) {
        markAllSorted(id, lastStep.arr);
        updateStats(id, lastStep.cmp, lastStep.swp, lastStep.steps);
      }
      setStatus(id, 'done', `✅ Done! ${(lastStep?.cmp || 0).toLocaleString()} comparisons`);
      onDone(lastStep);
      return;
    }
    const step = result.value;
    lastStep = step;
    updateChart(id, step.arr, step.highlights);
    updateStats(id, step.cmp, step.swp, step.steps);

    if (step.done) {
      markAllSorted(id, step.arr);
      setStatus(id, 'done', `✅ Done! ${step.cmp.toLocaleString()} comparisons`);
      onDone(step);
      return;
    }

    const handle = setTimeout(tick, delay);
    animFrames.push(handle);
  }

  tick();
}

// ─── Main Controls ────────────────────────────────────────────────────────────
let results = {};

function initAll() {
  const n = getSize();
  const order = getOrder();
  baseArray = generateArray(n, order);
  results = {};
  document.getElementById('verdict').style.display = 'none';

  ALGOS.forEach(id => {
    initChart(id, baseArray);
    updateStats(id, 0, 0, 0);
    setStatus(id, 'idle', 'Ready. Hit Start!');
  });
}

function startRace() {
  if (running) return;
  running = true;
  document.getElementById('startBtn').disabled = true;
  results = {};

  const arrays = {
    bubble: [...baseArray],
    merge:  [...baseArray],
    quick:  [...baseArray],
  };

  const gens = {
    bubble: bubbleSortGen(arrays.bubble),
    merge:  mergeSortGen(arrays.merge),
    quick:  quickSortGen(arrays.quick),
  };

  let doneCount = 0;

  function onDone(id, finalStep) {
    results[id] = finalStep;
    doneCount++;
    if (doneCount === 3) {
      running = false;
      document.getElementById('startBtn').disabled = false;
      showVerdict();
    }
  }

  ALGOS.forEach(id => {
    runAlgo(id, gens[id], (step) => onDone(id, step));
  });
}

function showVerdict() {
  const v = document.getElementById('verdict');
  v.style.display = 'block';

  const bCmp = results.bubble?.cmp || 0;
  const mCmp = results.merge?.cmp || 0;
  const qCmp = results.quick?.cmp || 0;
  const maxCmp = Math.max(bCmp, mCmp, qCmp, 1);

  const mergeRatio = (bCmp / Math.max(mCmp, 1)).toFixed(1);
  const quickRatio = (bCmp / Math.max(qCmp, 1)).toFixed(1);

  document.getElementById('verdict-text').innerHTML =
