    `Merge Sort needed <strong style="color:#44ff88">${mCmp.toLocaleString()}</strong> (${mergeRatio}× fewer). ` +
    `Quick Sort needed <strong style="color:#00ccff">${qCmp.toLocaleString()}</strong> (${quickRatio}× fewer). ` +
    `<br><br>Show this to your colleague. Frame it. Put it on their desk.`;

  const sbWrap = document.getElementById('speed-bars');
  sbWrap.innerHTML = `
