  Show this to your colleague. If they still insist on bubble sort, that's a HR issue, not a CS issue.<br>
  (Bubble sort is fine for teaching. For production data? Please no.)
</p>

<script>
// ─────────────────────────────────────────────
//  STATE
// ─────────────────────────────────────────────
let N = 40;
let running = false;
let originalArray = [];

let bubbleComps = 0, bubbleSwaps = 0, bubbleStart = 0, bubbleDone = false;
let mergeComps = 0,  mergeWrites = 0, mergeStart = 0,  mergeDone = false;
let quickComps = 0,  quickSwaps = 0,  quickStart = 0,  quickDone = false;

let bubbleArr = [], mergeArr = [], quickArr = [];
let bubbleGen, mergeGen, quickGen;

let animFrame = null;
let lastTick = 0;

function getDelay() {
  const s = parseInt(document.getElementById('speedSlider').value);
  // speed 1 = slow, 10 = fast
  // steps per frame: 1 to 50
  return Math.round(1 + (s - 1) * 5.4);
}

// ─────────────────────────────────────────────
//  ARRAY GENERATION
// ─────────────────────────────────────────────
function generateArray(n) {
  const arr = [];
  for (let i = 0; i < n; i++) arr.push(Math.floor(Math.random() * 95) + 5);
  return arr;
}

// ─────────────────────────────────────────────
//  CHART RENDERING
// ─────────────────────────────────────────────
function renderChart(containerId, arr, highlights = {}) {
  const container = document.getElementById(containerId);
  const bars = container.querySelectorAll('.bar');

  // Build bars if needed
  if (bars.length !== arr.length) {
    // Remove old bars (keep banner)
    container.querySelectorAll('.bar').forEach(b => b.remove());
    const maxVal = Math.max(...arr);
    arr.forEach((v, i) => {
      const bar = document.createElement('div');
      bar.className = 'bar';
      bar.style.height = ((v / maxVal) * 100) + '%';
      bar.style.background = getBarColor(containerId, i, highlights);
      container.appendChild(bar);
    });
    return;
  }

  const maxVal = Math.max(...arr);
  bars.forEach((bar, i) => {
    bar.style.height = ((arr[i] / maxVal) * 100) + '%';
    bar.style.background = getBarColor(containerId, i, highlights);
  });
}

function getBarColor(chartId, index, highlights) {
  if (highlights.comparing && highlights.comparing.includes(index)) return '#ffffff';
  if (highlights.sorted && highlights.sorted.includes(index)) {
    if (chartId === 'bubble-chart') return '#ff6666';
    if (chartId === 'merge-chart')  return '#00ff88';
    if (chartId === 'quick-chart')  return '#00aaff';
  }
  if (chartId === 'bubble-chart') return '#552222';
  if (chartId === 'merge-chart')  return '#1a4433';
  if (chartId === 'quick-chart')  return '#1a3344';
  return '#333';
}

function initCharts() {
  ['bubble-chart', 'merge-chart', 'quick-chart'].forEach((id, idx) => {
    const arr = idx === 0 ? bubbleArr : idx === 1 ? mergeArr : quickArr;
    const container = document.getElementById(id);
    container.querySelectorAll('.bar').forEach(b => b.remove());
    const maxVal = Math.max(...arr);
    arr.forEach(v => {
      const bar = document.createElement('div');
      bar.className = 'bar';
      bar.style.height = ((v / maxVal) * 100) + '%';
      bar.style.background = id === 'bubble-chart' ? '#552222' :
                              id === 'merge-chart'  ? '#1a4433' : '#1a3344';
      container.appendChild(bar);
    });
  });
}

// ─────────────────────────────────────────────
//  BUBBLE SORT GENERATOR
// ─────────────────────────────────────────────
function* bubbleSortGen(arr) {
  const n = arr.length;
  const sortedIndices = new Set();
  for (let i = 0; i < n - 1; i++) {
    let swapped = false;
    for (let j = 0; j < n - i - 1; j++) {
      bubbleComps++;
      yield { comparing: [j, j+1], sorted: [...sortedIndices] };
      if (arr[j] > arr[j+1]) {
        [arr[j], arr[j+1]] = [arr[j+1], arr[j]];
        bubbleSwaps++;
        swapped = true;
        yield { comparing: [j, j+1], sorted: [...sortedIndices] };
      }
    }
    sortedIndices.add(n - 1 - i);
    if (!swapped) break;
  }
  // Mark all sorted
  for (let k = 0; k < n; k++) sortedIndices.add(k);
  yield { comparing: [], sorted: [...sortedIndices], done: true };
}

// ─────────────────────────────────────────────
//  MERGE SORT GENERATOR
// ─────────────────────────────────────────────
function* mergeSortGen(arr) {
  const n = arr.length;
  const aux = arr.slice();

  function* mergeSort(lo, hi) {
    if (hi - lo < 1) return;
    const mid = Math.floor((lo + hi) / 2);
    yield* mergeSort(lo, mid);
    yield* mergeSort(mid + 1, hi);
    yield* merge(lo, mid, hi);
  }

  function* merge(lo, mid, hi) {
    for (let k = lo; k <= hi; k++) aux[k] = arr[k];
    let i = lo, j = mid + 1;
    for (let k = lo; k <= hi; k++) {
      mergeComps++;
      if (i > mid) {
        arr[k] = aux[j++]; mergeWrites++;
      } else if (j > hi) {
        arr[k] = aux[i++]; mergeWrites++;
      } else if (aux[j] < aux[i]) {
        arr[k] = aux[j++]; mergeWrites++; mergeComps++;
      } else {
        arr[k] = aux[i++]; mergeWrites++;
      }
      yield { comparing: [k, i > lo ? i-1 : lo, j > mid+1 ? j-1 : mid+1], sorted: [] };
    }
  }

  yield* mergeSort(0, n - 1);

  const allIdx = Array.from({length: n}, (_, i) => i);
  yield { comparing: [], sorted: allIdx, done: true };
}

// ─────────────────────────────────────────────
//  QUICK SORT GENERATOR
// ─────────────────────────────────────────────
function* quickSortGen(arr) {
  const n = arr.length;

  function* quickSort(lo, hi) {
    if (lo >= hi) return;
    const p = yield* partition(lo, hi);
    yield* quickSort(lo, p - 1);
    yield* quickSort(p + 1, hi);
  }

  function* partition(lo, hi) {
    // median-of-3 pivot
    const mid = Math.floor((lo + hi) / 2);
    if (arr[mid] < arr[lo]) { [arr[lo], arr[mid]] = [arr[mid], arr[lo]]; quickSwaps++; }
    if (arr[hi]  < arr[lo]) { [arr[lo], arr[hi]]  = [arr[hi],  arr[lo]]; quickSwaps++; }
    if (arr[mid] < arr[hi]) { [arr[mid], arr[hi]] = [arr[hi], arr[mid]]; quickSwaps++; }
    const pivot = arr[hi];
    let i = lo - 1;
    for (let j = lo; j < hi; j++) {
      quickComps++;
      yield { comparing: [j, hi], sorted: [] };
      if (arr[j] <= pivot) {
        i++;
        [arr[i], arr[j]] = [arr[j], arr[i]];
        quickSwaps++;
        yield { comparing: [i, j], sorted: [] };
      }
    }
    [arr[i+1], arr[hi]] = [arr[hi], arr[i+1]];
    quickSwaps++;
    yield { comparing: [i+1, hi], sorted: [] };
    return i + 1;
  }

  yield* quickSort(0, n - 1);

  const allIdx = Array.from({length: n}, (_, i) => i);
  yield { comparing: [], sorted: allIdx, done: true };
}

// ─────────────────────────────────────────────
//  RACE BAR UPDATE
// ─────────────────────────────────────────────
function updateRaceBars() {
  const bOps = bubbleComps + bubbleSwaps;
  const mOps = mergeComps + mergeWrites;
  const qOps = quickComps + quickSwaps;
  const maxOps = Math.max(bOps, mOps, qOps, 1);

  const bPct = (bOps / maxOps * 100).toFixed(1);
  const mPct = (mOps / maxOps * 100).toFixed(1);
  const qPct = (qOps / maxOps * 100).toFixed(1);

  document.getElementById('race-bubble').style.width = bPct + '%';
  document.getElementById('race-merge').style.width  = mPct + '%';
  document.getElementById('race-quick').style.width  = qPct + '%';

  document.getElementById('race-bubble-count').textContent = bOps.toLocaleString() + ' ops';
  document.getElementById('race-merge-count').textContent  = mOps.toLocaleString() + ' ops';
  document.getElementById('race-quick-count').textContent  = qOps.toLocaleString() + ' ops';
}

// ─────────────────────────────────────────────
//  MAIN ANIMATION LOOP
// ─────────────────────────────────────────────
function tick() {
  if (!running) return;

  const steps = getDelay();

  for (let s = 0; s < steps; s++) {
    if (!bubbleDone) stepBubble();
    if (!mergeDone)  stepMerge();
    if (!quickDone)  stepQuick();
  }

  updateRaceBars();
  updateTimers();

  if (bubbleDone && mergeDone && quickDone) {
    running = false;
    showVerdict();
    return;
  }

  animFrame = requestAnimationFrame(tick);
}

function stepBubble() {
  const result = bubbleGen.next();
  if (result.done || (result.value && result.value.done)) {
    bubbleDone = true;
    bubbleArr; // already sorted in place
    renderChart('bubble-chart', bubbleArr, { comparing: [], sorted: Array.from({length: bubbleArr.length}, (_, i) => i) });
    showDoneBanner('bubble');
    document.getElementById('bubble-status').textContent = `😮‍💨 Done. ${(bubbleComps + bubbleSwaps).toLocaleString()} total operations.`;
    return;
  }
  const { comparing, sorted } = result.value;
  renderChart('bubble-chart', bubbleArr, { comparing, sorted });
  document.getElementById('bubble-comps').textContent = bubbleComps.toLocaleString();
  document.getElementById('bubble-swaps').textContent = bubbleSwaps.toLocaleString();
}

function stepMerge() {
  const result = mergeGen.next();
  if (result.done || (result.value && result.value.done)) {
    mergeDone = true;
    renderChart('merge-chart', mergeArr, { comparing: [], sorted: Array.from({length: mergeArr.length}, (_, i) => i) });
    showDoneBanner('merge');
    document.getElementById('merge-status').textContent = `✅ Done. ${(mergeComps + mergeWrites).toLocaleString()} total operations.`;
    return;
  }
  const { comparing, sorted } = result.value;
  renderChart('merge-chart', mergeArr, { comparing, sorted });
  document.getElementById('merge-comps').textContent  = mergeComps.toLocaleString();
  document.getElementById('merge-writes').textContent = mergeWrites.toLocaleString();
}

function stepQuick() {
  const result = quickGen.next();
  if (result.done || (result.value && result.value.done)) {
    quickDone = true;
    renderChart('quick-chart', quickArr, { comparing: [], sorted: Array.from({length: quickArr.length}, (_, i) => i) });
    showDoneBanner('quick');
    document.getElementById('quick-status').textContent = `🏆 Done. ${(quickComps + quickSwaps).toLocaleString()} total operations.`;
    return;
  }
  const { comparing, sorted } = result.value;
  renderChart('quick-chart', quickArr, { comparing, sorted });
  document.getElementById('quick-comps').textContent = quickComps.toLocaleString();
  document.getElementById('quick-swaps').textContent = quickSwaps.toLocaleString();
}

function updateTimers() {
  const now = performance.now();
  if (!bubbleDone) document.getElementById('bubble-time').textContent = Math.round(now - bubbleStart) + 'ms';
  if (!mergeDone)  document.getElementById('merge-time').textContent  = Math.round(now - mergeStart)  + 'ms';
  if (!quickDone)  document.getElementById('quick-time').textContent  = Math.round(now - quickStart)  + 'ms';
}

function showDoneBanner(algo) {
  const now = performance.now();
  const banner = document.getElementById(algo + '-banner');
  banner.classList.add('visible');

  if (algo === 'bubble') {
    document.getElementById('bubble-time').textContent = Math.round(now - bubbleStart) + 'ms';
    document.getElementById('bubble-final-stats').textContent =
      `${bubbleComps.toLocaleString()} comparisons · ${bubbleSwaps.toLocaleString()} swaps`;
  } else if (algo === 'merge') {
    document.getElementById('merge-time').textContent = Math.round(now - mergeStart) + 'ms';
    document.getElementById('merge-final-stats').textContent =
      `${mergeComps.toLocaleString()} comparisons · ${mergeWrites.toLocaleString()} writes`;
  } else {
    document.getElementById('quick-time').textContent = Math.round(now - quickStart) + 'ms';
    document.getElementById('quick-final-stats').textContent =
      `${quickComps.toLocaleString()} comparisons · ${quickSwaps.toLocaleString()} swaps`;
  }
}

function showVerdict() {
  const bOps = bubbleComps + bubbleSwaps;
  const mOps = mergeComps + mergeWrites;
  const qOps = quickComps + quickSwaps;
  const ratio = (bOps / Math.min(mOps, qOps)).toFixed(1);

  const verdicts = [
    `Bubble sort used ${ratio}x more operations. Your colleague owes everyone an apology.`,
    `Bubble sort: ${bOps.toLocaleString()} ops. The others: way less. Case closed.`,
    `That's ${ratio}x the work for the same result. Bubble sort is the intern of algorithms.`,
    `Bubble sort called. It's embarrassed. ${ratio}x more operations than necessary.`,
  ];
  document.getElementById('verdict').textContent =
    '🔥 ' + verdicts[Math.floor(Math.random() * verdicts.length)];
}

// ─────────────────────────────────────────────
//  CONTROLS
// ─────────────────────────────────────────────
function startAll() {
  if (running) return;

  // Reset stats
  bubbleComps = bubbleSwaps = mergeComps = mergeWrites = quickComps = quickSwaps = 0;
  bubbleDone = mergeDone = quickDone = false;

  document.getElementById('bubble-comps').textContent = '0';
  document.getElementById('bubble-swaps').textContent = '0';
  document.getElementById('bubble-time').textContent  = '0ms';
  document.getElementById('merge-comps').textContent  = '0';
  document.getElementById('merge-writes').textContent = '0';
  document.getElementById('merge-time').textContent   = '0ms';
  document.getElementById('quick-comps').textContent  = '0';
  document.getElementById('quick-swaps').textContent  = '0';
  document.getElementById('quick-time').textContent   = '0ms';

  document.getElementById('bubble-status').textContent = 'Suffering...';
  document.getElementById('merge-status').textContent  = 'Dividing and conquering...';
  document.getElementById('quick-status').textContent  = 'Pivoting to victory...';
  document.getElementById('verdict').textContent = '';

  ['bubble', 'merge', 'quick'].forEach(a => {
    document.getElementById(a + '-banner').classList.remove('visible');
  });

  bubbleGen = bubbleSortGen(bubbleArr);
  mergeGen  = mergeSortGen(mergeArr);
  quickGen  = quickSortGen(quickArr);

  const now = performance.now();
  bubbleStart = mergeStart = quickStart = now;

  running = true;
  animFrame = requestAnimationFrame(tick);
}

function resetAll() {
  running = false;
  if (animFrame) cancelAnimationFrame(animFrame);

  bubbleComps = bubbleSwaps = mergeComps = mergeWrites = quickComps = quickSwaps = 0;
  bubbleDone = mergeDone = quickDone = false;

  originalArray = generateArray(N);
  bubbleArr = originalArray.slice();
  mergeArr  = originalArray.slice();
  quickArr  = originalArray.slice();

  initCharts();

  document.getElementById('bubble-comps').textContent = '0';
  document.getElementById('bubble-swaps').textContent = '0';
  document.getElementById('bubble-time').textContent  = '0ms';
  document.getElementById('merge-comps').textContent  = '0';
  document.getElementById('merge-writes').textContent = '0';
  document.getElementById('merge-time').textContent   = '0ms';
  document.getElementById('quick-comps').textContent  = '0';
  document.getElementById('quick-swaps').textContent  = '0';
  document.getElementById('quick-time').textContent   = '0ms';

  document.getElementById('bubble-status').textContent = 'Ready to suffer.';
  document.getElementById('merge-status').textContent  = 'Ready to demolish bubble sort.';
  document.getElementById('quick-status').textContent  = 'Ready to make bubble sort cry.';
  document.getElementById('verdict').textContent = '';

  document.getElementById('race-bubble').style.width = '0%';
  document.getElementById('race-merge').style.width  = '0%';
  document.getElementById('race-quick').style.width  = '0%';
  document.getElementById('race-bubble-count').textContent = '0 ops';
  document.getElementById('race-merge-count').textContent  = '0 ops';
  document.getElementById('race-quick-count').textContent  = '0 ops';

  ['bubble', 'merge', 'quick'].forEach(a => {
    document.getElementById(a + '-banner').classList.remove('visible');
  });
}

function onSizeChange(val) {
  N = parseInt(val);
  document.getElementById('sizeLabel').textContent = N;
  if (!running) resetAll();
}

// ─────────────────────────────────────────────
//  INIT
// ─────────────────────────────────────────────
resetAll();
</script>
</body>
</html>
```

## What this does:

| Feature | Details |
|---|---|
| **3 side-by-side panels** | Bubble Sort, Merge Sort, Quick Sort racing on identical data |
| **Live bar charts** | Animated with color-coded highlights for active comparisons |
| **Step counters** | Comparisons, swaps/writes, and elapsed time per algorithm |
| **Operation race bar** | Horizontal bar chart showing cumulative ops — bubble runs away to the right in shame |
| **Done banners** | Each panel shows a completion message when finished |
| **Verdict generator** | Calculates the multiplier by which bubble sort lost and roasts it |
| **Complexity table** | Big-O reference for all three algorithms |
| **Controls** | Array size (20–80 elements), speed slider, start/reset buttons |

Save it as a `.html` file and open it in any browser. Hit **START THE CARNAGE** and watch bubble sort embarrass itself. 🎉
